//! x86_64 user/ring boundary (M4): drop the CPU to ring 3, run a tiny user
//! stub there, have it `int 0x80` back into the kernel, handle the syscall in
//! safe-ish tb-hal Rust, and return the round-trip verdict. ALL of M4's
//! x86_64 `unsafe`/asm lives HERE (plus the small descriptor edits in
//! `gdt.rs`/`idt.rs`); the kernel crate stays `#![forbid(unsafe_code)]`
//! (KERNEL-FOUNDATION-SPEC §1) and only calls the safe [`user_demo`].
//!
//! THE ROUND TRIP (M4-v1 uses the EXISTING trap mechanism — a DPL=3 IDT gate
//! for `int 0x80` — NOT the SYSCALL/SYSRET fast path, which is a deferred
//! optimization):
//!
//!  1. [`user_demo`] maps a fresh, ring3-accessible code page + stack page
//!     (`USER_CODE_VA` / `USER_STACK_VA`) into the LIVE CR3 hierarchy via the
//!     M3 typed table layer, with `U/S = 1` (bit 2) on EVERY level of the walk
//!     (PML4E→PDPTE→PDE→PTE) — supervisor-only entries would `#PF` the moment
//!     ring3 touches them (Intel SDM Vol.3A §4.6 "Access Rights": a user-mode
//!     access is allowed only if `U/S = 1` in *every* paging-structure entry
//!     controlling the translation). The boot map's `PML4[0]` is `U/S = 0`, so
//!     we deliberately place the user range in a SEPARATE, vacant PML4 slot
//!     (`0x0000_0080_0000_0000` → `PML4[1]`) and build our OWN
//!     PML4E/PDPTE/PDE/PTE chain with `U/S = 1` throughout.
//!  2. The code page is loaded with the bytes of [`enter_ring3`]'s companion
//!     stub `user_stub` (a position-independent naked fn: `mov rax,0xCAFE;
//!     int 0x80; jmp .`). The stub is COPIED into an isolated, page-aligned
//!     `.bss` frame (sourced via the stub's identity-mapped symbol) rather
//!     than aliasing the kernel `.text` page into ring3 — this keeps ring3
//!     from reading neighbouring kernel code and sidesteps any page-straddle.
//!  3. [`enter_ring3`] parks the kernel callee-saved registers, records the
//!     kernel resume SP, builds the `iret` frame `[SS, RSP, RFLAGS, CS, RIP]`
//!     and `iretq`s into ring3 at `USER_CODE_VA`. Verified `iretq` pop order
//!     (Intel SDM Vol.2 IRET/IRETD/IRETQ "Operation", IA-32e 64-bit path):
//!     `RIP := Pop(); CS := Pop(); tempRFLAGS := Pop();` then, because
//!     `CS.RPL (3) > CPL (0)`, RETURN-TO-OUTER-PRIVILEGE-LEVEL does
//!     `tempRSP := Pop(); tempSS := Pop();` — so the frame is BUILT by pushing
//!     SS, RSP, RFLAGS, CS, RIP in that order (RIP ends up on top).
//!  4. The stub issues `int 0x80`. The CPU sees a ring3→ring0 privilege change
//!     so it loads RSP from `TSS.RSP0` (programmed in `gdt::init`; Intel SDM
//!     Vol.3A §6.14.4 / §7.7 Fig 7-11, RSP0 at TSS byte offset 0x04), pushes
//!     the interrupt frame there, and vectors through the DPL=3 gate
//!     (`idt::set_user_gate`, type_attr 0xEE) into [`syscall_entry`].
//!  5. [`syscall_entry`] reads the syscall arg from `rax` (= `0xCAFE`), calls
//!     the Rust [`x86_syscall_handler`] (records the arg, prints
//!     `syscall from user: arg=0x...`, sets the seen flag), then performs a
//!     NON-LOCAL RETURN into the kernel: it abandons the RSP0 frame, reloads
//!     the resume SP `enter_ring3` parked, pops the kernel callee-saved set
//!     and `ret`s — so control lands back in [`user_demo`] exactly as if
//!     `enter_ring3` had returned. We never `iretq` back to ring3 (the stub's
//!     `jmp .` would just spin); the syscall IS the kernel re-entry. This is
//!     the spec's "set the flag and resume into a kernel landing point"
//!     design, realized as a direct stack switch (no iret frame rewrite, so
//!     no kernel SS/CS to fabricate).
//!  6. [`user_demo`] returns `true` iff the syscall was observed from ring3
//!     with the expected arg.
//!
//! VERIFIED FACTS quoted from primary sources (do NOT change these without
//! re-reading them):
//!   * `iretq` inter-privilege frame `[SS, RSP, RFLAGS, CS, RIP]` + pop order:
//!     Intel SDM Vol.2A "IRET/IRETD/IRETQ — Interrupt Return", Operation
//!     pseudocode (IA-32e mode, OperandSize 64 → RIP/CS/tempRFLAGS popped,
//!     then RETURN-TO-OUTER-PRIVILEGE-LEVEL pops tempRSP/tempSS); OSDev
//!     "Getting to Ring 3".
//!   * Ring3 GDT descriptors — access byte `0xFA` user code
//!     (P=1,DPL=3,S=1,E=1,RW=1) and `0xF2` user data (P=1,DPL=3,S=1,RW=1);
//!     selectors loaded with `RPL = 3`: Intel SDM Vol.3A §3.4.5 Fig 3-8
//!     "Segment Descriptor"; §5.5/§5.8.1 (RPL/DPL/CPL). See `gdt.rs`.
//!   * `int n` from ring3 needs the gate's `DPL >= CPL` — gate DPL=3
//!     (type_attr `0xEE`): Intel SDM Vol.3A §6.12.1.2 "the processor checks
//!     that the CPL is less than or equal to the DPL of the [interrupt/trap]
//!     gate"; Fig 6-8 "64-Bit IDT Gate Descriptors". See `idt.rs`.
//!   * `TSS.RSP0` is loaded on the ring3→ring0 stack switch: Intel SDM Vol.3A
//!     §6.14.4 "Stack Switching", §7.7 Fig 7-11 (RSP0 at byte 0x04). See
//!     `gdt.rs`.
//!   * Paging `U/S` (bit 2) required at EVERY level for ring3 access: Intel
//!     SDM Vol.3A §4.6 "Access Rights"; bit positions cross-checked against
//!     Linux v6.6 `arch/x86/include/asm/pgtable_types.h` (`_PAGE_BIT_USER 2`,
//!     `_PAGE_BIT_NX 63`). NX (bit 63) is honoured because M3's `mmu_init`
//!     already set `IA32_EFER.NXE`.

use core::arch::{asm, global_asm, naked_asm};
use core::cell::UnsafeCell;
use core::ptr::{addr_of, copy_nonoverlapping, write_volatile};
use core::sync::atomic::{AtomicBool, AtomicU64, Ordering};

use crate::mmu::PageTable512;

use super::gdt;
use super::idt;

// ---------------------------------------------------------------------------
// Architectural constants (verified — see module header).
// ---------------------------------------------------------------------------

/// Paging-entry bit 0: Present (Intel SDM Vol.3A Table 4-15; Linux
/// `_PAGE_BIT_PRESENT 0`).
const PTE_P: u64 = 1 << 0;
/// Paging-entry bit 1: Read/Write (Linux `_PAGE_BIT_RW 1`).
const PTE_RW: u64 = 1 << 1;
/// Paging-entry bit 2: User/Supervisor — MUST be 1 at every level for ring3
/// access (Intel SDM Vol.3A §4.6; Linux `_PAGE_BIT_USER 2`).
const PTE_US: u64 = 1 << 2;
/// Paging-entry bit 63: Execute-Disable (honoured because `mmu_init` set
/// `IA32_EFER.NXE`; Linux `_PAGE_BIT_NX 63`).
const PTE_NX: u64 = 1 << 63;

/// Physical-address field of any paging entry: bits 51:12 (Intel SDM Vol.3A
/// Table 4-15). Masking strips flag/ignored bits when walking CR3.
const PTE_ADDR_MASK: u64 = 0x000F_FFFF_FFFF_F000;

/// User code virtual address: 2^39 = `PML4[1]` — a SEPARATE, vacant PML4 slot
/// from the boot map's `PML4[0]` (which is `U/S = 0` and cannot be reused for
/// ring3). Canonical (bits 63:48 = sign-extension of bit 47 = 0).
const USER_CODE_VA: usize = 0x0000_0080_0000_0000;
/// User stack virtual address: the next page after the code page.
const USER_STACK_VA: usize = USER_CODE_VA + 0x1000;
/// Initial ring3 RSP: the exclusive top of the (one-page) user stack. Stacks
/// grow down, so the first push lands at `USER_STACK_TOP - 8`, inside the
/// mapped page. 16-aligned (SysV), though the stub never touches the stack.
const USER_STACK_TOP: u64 = (USER_STACK_VA + 0x1000) as u64;

/// `USER_CODE_VA`'s PML4 index (VA bits 47:39) — `1`, the vacant slot.
const PML4_IDX: usize = (USER_CODE_VA >> 39) & 0x1FF;
/// `USER_CODE_VA`'s PDPT index (VA bits 38:30) — `0`.
const PDPT_IDX: usize = (USER_CODE_VA >> 30) & 0x1FF;
/// `USER_CODE_VA`'s PD index (VA bits 29:21) — `0`.
const PD_IDX: usize = (USER_CODE_VA >> 21) & 0x1FF;
/// `USER_CODE_VA`'s PT index (VA bits 20:12) — `0`.
const CODE_PT_IDX: usize = (USER_CODE_VA >> 12) & 0x1FF;
/// `USER_STACK_VA`'s PT index (VA bits 20:12) — `1` (same PML4/PDPT/PD chain).
const STACK_PT_IDX: usize = (USER_STACK_VA >> 12) & 0x1FF;

/// IDT vector the user stub traps through (the classic Linux `int 0x80`).
const SYSCALL_VECTOR: usize = 0x80;

/// The magic syscall argument the user stub passes in `rax`; observing it in
/// ring0 proves we genuinely trapped back FROM ring3 (b"...0xCAFE").
const EXPECTED_ARG: u64 = 0xCAFE;

/// Ring3 `RFLAGS`: reserved bit 1 (always 1) + IF (bit 9). There is no IRQ
/// source wired in the QEMU `microvm` we target, and the stub executes only
/// two instructions before `int 0x80`, so IF=1 is safe (Intel SDM Vol.1
/// §3.4.3 EFLAGS). This matches the M4 spec's `0x202`.
const USER_RFLAGS: u64 = 0x202;

// ---------------------------------------------------------------------------
// Round-trip observation state (single-vCPU, interrupts masked since boot).
// ---------------------------------------------------------------------------

/// Set by [`x86_syscall_handler`] when the syscall is observed from ring3.
static SYSCALL_SEEN: AtomicBool = AtomicBool::new(false);
/// The syscall arg captured from the user `rax` (expected [`EXPECTED_ARG`]).
static SYSCALL_ARG: AtomicU64 = AtomicU64::new(0);

/// Kernel stack pointer parked by [`enter_ring3`] and reloaded by
/// [`syscall_entry`] to perform the non-local return into the kernel. Touched
/// ONLY from the two naked-asm bodies (never via a Rust reference), so a plain
/// `static mut` reached by `sym` is the cleanest channel and raises no
/// `static_mut_refs` concern (we take its address, never a reference).
static mut KERNEL_RESUME_SP: u64 = 0;

// ---------------------------------------------------------------------------
// Static 4 KiB cells (.bss): the user PDPT/PD/PT chain + the code/stack pages.
// ---------------------------------------------------------------------------

/// A 4096-aligned, interior-mutable 4 KiB cell that lives in an immutable
/// `static` (zero-initialised → `.bss`, cleared by the boot trampoline) while
/// tb-hal mutates it through raw pointers. Reuses the shared typed layout
/// [`PageTable512`] (`#[repr(C, align(4096))]` over `[u64; 512]`) for both the
/// new paging tables and the data pages (a code/stack page is just 4 KiB of
/// `.bss`). Mirrors the same pattern as `mmu.rs` (kept module-local so M4's
/// edits stay confined to the files M4 owns).
#[repr(C)]
struct Cell4K(UnsafeCell<PageTable512>);

// SAFETY: M4 is single-vCPU with interrupts masked since boot; every access to
// the interior goes through raw pointers from `UnsafeCell::get` (no `&`/`&mut`
// to the interior is ever materialised), so sharing the cell via an immutable
// `static` cannot violate aliasing. `UnsafeCell` is what makes in-place
// mutation behind an immutable `static` defined behaviour.
unsafe impl Sync for Cell4K {}

impl Cell4K {
    /// A new zeroed cell; `const`, so it can initialise a `static` in `.bss`.
    const fn new() -> Self {
        Cell4K(UnsafeCell::new(PageTable512([0; 512])))
    }

    /// Raw pointer to the 8-byte entry `idx` of this cell (`idx < 512`).
    fn entry_ptr(&self, idx: usize) -> *mut u64 {
        debug_assert!(idx < 512);
        // SAFETY: `idx < 512` keeps the offset inside this one 4096-byte
        // allocation; `PageTable512` is `repr(C, align(4096))` over
        // `[u64; 512]`, so the element cast + offset is layout-exact.
        unsafe { (self.0.get() as *mut u64).add(idx) }
    }

    /// Raw byte pointer to the start of this cell (used to stage the stub).
    fn byte_ptr(&self) -> *mut u8 {
        self.0.get() as *mut u8
    }

    /// PHYSICAL base address of this cell (virtual == physical: the kernel
    /// image and its `.bss` are loaded at 1 MiB and the boot tables
    /// identity-map [0, 1 GiB)). 4096-aligned, so it drops straight into the
    /// bits-51:12 address field of a paging entry.
    fn phys_base(&self) -> u64 {
        self.0.get() as u64
    }
}

/// New PDPT hung off the live `PML4[1]`.
static USER_PDPT: Cell4K = Cell4K::new();
/// New PD behind `USER_PDPT[0]`.
static USER_PD: Cell4K = Cell4K::new();
/// New PT behind `USER_PD[0]`, holding the code + stack leaf PTEs.
static USER_PT: Cell4K = Cell4K::new();
/// The ring3 code page — the user stub is copied here, mapped P|U (exec).
static USER_CODE: Cell4K = Cell4K::new();
/// The ring3 stack page — mapped P|RW|U|NX.
static USER_STACK: Cell4K = Cell4K::new();

// ===========================================================================
// The position-independent ring3 user stub.
// (a) PRE: entered in ring3 at USER_CODE_VA with a valid user SS:RSP. POST:
//     loads the magic arg into rax, traps to the kernel via `int 0x80`; the
//     kernel does NOT return here (it longjmps back to the kernel), so the
//     trailing `jmp .` is an unreachable safety spin.
// (b) ABI: PURE position-independent code — `mov rax,imm` (B8/48C7C0),
//     `int 0x80` (CD 80), `jmp .` (EB FE) — no absolute/RIP refs, so it runs
//     correctly at the aliased USER_CODE_VA after being COPIED there. Intel
//     syntax (Rust default). `.text.user` is matched by the linker's
//     `*(.text .text.*)`, landing in the identity-mapped, ring0-readable
//     `.text` so the copy source is reachable.
// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK"; the kernel only
//     prints it after `user_demo` observes arg=0xCAFE FROM ring3).
// ===========================================================================
global_asm!(
    r#"
.section .text.user, "ax", @progbits
.balign 16
.global user_stub_start
.global user_stub_end
user_stub_start:
    mov rax, 0xCAFE         // syscall arg → rax (proves the trap came from us)
    int 0x80                // ring3 → ring0 via the DPL=3 vector-0x80 gate
2:
    jmp 2b                  // unreachable: the kernel longjmps, never iretq's back
user_stub_end:
"#
);

extern "C" {
    /// First byte of the ring3 stub (its identity-mapped symbol = its phys).
    static user_stub_start: u8;
    /// One-past-the-last byte of the ring3 stub.
    static user_stub_end: u8;
}

// ---------------------------------------------------------------------------
// Privileged register wrappers: the M4-local paging pokes (CR3 read + invlpg).
// (mmu.rs has equivalents, but they are private to that module; keeping these
// here confines M4's edits to the files M4 owns.)
// ---------------------------------------------------------------------------

/// Read CR3 — physical base of the live PML4 (plus PWT/PCD bits we mask off).
///
/// (a) PRE: long mode, ring 0. POST: returns live CR3; no state change.
/// (b) ABI: `mov {out}, cr3`; one GPR out; no flags; nomem/nostack.
/// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK" — used to splice
///     `PML4[1]` into the live hierarchy).
#[inline]
unsafe fn read_cr3() -> u64 {
    let val: u64;
    // SAFETY: ring-0-only read; caller is inside tb-hal.
    unsafe {
        asm!("mov {}, cr3", out(reg) val, options(nomem, nostack, preserves_flags));
    }
    val
}

/// `invlpg [va]` — invalidate any TLB entry for the page containing `va`.
///
/// (a) PRE: ring 0, paging on. POST: next access to `va` re-walks the tables.
/// (b) ABI: `invlpg [{in}]`; address operand only (never dereferenced as
///     data); no flags; NOT nomem (must order vs surrounding accesses).
/// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK"). Strictly
///     belt-and-suspenders here: building `PML4[1]` is a 0→1 Present
///     transition, which needs no invalidation (Intel SDM Vol.3A §4.10.4.3).
#[inline]
unsafe fn invlpg(va: usize) {
    // SAFETY: ring-0-only; see (a).
    unsafe {
        asm!("invlpg [{}]", in(reg) va, options(nostack, preserves_flags));
    }
}

// ---------------------------------------------------------------------------
// Build the ring3 mapping: copy the stub, then splice a U/S=1 chain into CR3.
// ---------------------------------------------------------------------------

/// Stage the user code page and splice a ring3-accessible
/// `PML4[1]→PDPT[0]→PD[0]→PT[{0,1}]` chain into the LIVE CR3 hierarchy, with
/// `U/S = 1` on every level (Intel SDM Vol.3A §4.6). Built bottom-up and
/// PUBLISHED LAST (PML4 entry written after the subtree is complete) so the
/// page walker can never observe a half-built chain.
///
/// # Safety
/// Ring 0, single vCPU, interrupts masked. The five `Cell4K` statics are
/// tb-hal-owned and reached ONLY through `UnsafeCell` raw pointers, so no Rust
/// reference aliases the memory the CPU walker / ring3 alias touch. `PML4[1]`
/// is vacant in the boot map (boot uses only `PML4[0]`), so this adds a brand
/// new translation and disturbs nothing M0–M3 built.
unsafe fn map_user_pages() {
    // Copy the PIC stub into the isolated, page-aligned code frame (sourced via
    // its identity-mapped symbol; written through the frame's identity address,
    // a ring0 RW boot mapping — so SMAP, were it on, would not apply).
    let src = addr_of!(user_stub_start) as *const u8;
    let len = (addr_of!(user_stub_end) as usize) - (src as usize);
    debug_assert!(len <= 4096, "user stub must fit in one page");
    // SAFETY: `src` spans [user_stub_start, user_stub_end) in identity-mapped,
    // ring0-readable `.text`; `len <= 4096` keeps the write inside the one
    // 4 KiB `USER_CODE` frame; regions do not overlap.
    unsafe {
        copy_nonoverlapping(src, USER_CODE.byte_ptr(), len);
    }

    // SAFETY: every pointer below is a 4096-aligned tb-hal static or the live
    // PML4 read from CR3; all stores are volatile so the compiler neither
    // elides nor reorders them around the publish-last ordering.
    unsafe {
        // Leaves first. Code: P|U, NX clear (ring3 may fetch/execute), no RW
        // (the stub is never written from ring3). Stack: P|RW|U|NX.
        write_volatile(
            USER_PT.entry_ptr(CODE_PT_IDX),
            USER_CODE.phys_base() | PTE_P | PTE_US,
        );
        write_volatile(
            USER_PT.entry_ptr(STACK_PT_IDX),
            USER_STACK.phys_base() | PTE_P | PTE_RW | PTE_US | PTE_NX,
        );
        // Interior tables: P|RW|U (U/S=1 required at every level).
        write_volatile(
            USER_PD.entry_ptr(PD_IDX),
            USER_PT.phys_base() | PTE_P | PTE_RW | PTE_US,
        );
        write_volatile(
            USER_PDPT.entry_ptr(PDPT_IDX),
            USER_PD.phys_base() | PTE_P | PTE_RW | PTE_US,
        );
        // Publish last: splice into the live PML4 at the vacant slot 1.
        let pml4 = (read_cr3() & PTE_ADDR_MASK) as *mut u64;
        write_volatile(
            pml4.add(PML4_IDX),
            USER_PDPT.phys_base() | PTE_P | PTE_RW | PTE_US,
        );
        // 0→1 Present needs no flush (SDM §4.10.4.3); cheap insurance anyway.
        invlpg(USER_CODE_VA);
        invlpg(USER_STACK_VA);
    }
}

// ===========================================================================
// enter_ring3: drop CPL 0 → 3 via iretq, parking a kernel resume point.
// (a) PRE: called like a normal extern "C" fn (rdi=user RIP, rsi=user RSP,
//     rdx=user CS|3, rcx=user SS|3); GDT has the DPL3 user descriptors and
//     TSS.RSP0 is valid; USER_CODE/STACK mapped U/S=1. POST: does NOT return
//     normally — `iretq` transfers to ring3 at the stub. Control re-enters the
//     kernel only via `syscall_entry`, which restores the parked callee-saved
//     frame and `ret`s, so from the caller's view this fn returned normally.
// (b) ABI: SysV extern "C"; Intel syntax (Rust default). Saves the psABI
//     callee-saved set {rbx,rbp,r12-r15} so the syscall longjmp can hand the
//     caller back an intact register file; caller-saved regs are dead across
//     a call. iret frame order [SS,RSP,RFLAGS,CS,RIP] per Intel SDM Vol.2 IRET
//     (pops RIP,CS,RFLAGS then, for the outer-privilege return, RSP,SS).
// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK").
// ===========================================================================
#[unsafe(naked)]
unsafe extern "C" fn enter_ring3(user_rip: u64, user_rsp: u64, user_cs: u64, user_ss: u64) {
    naked_asm!(
        // Park the kernel's callee-saved context on the current kernel stack.
        "push rbx",
        "push rbp",
        "push r12",
        "push r13",
        "push r14",
        "push r15",
        // Record the resume SP (top of the parked frame) for syscall_entry.
        "lea rax, [rip + {resume_sp}]",
        "mov [rax], rsp",
        // Build the inter-privilege iret frame, then drop to ring3.
        "push rcx",            // SS     = user_ss (user data | RPL3)
        "push rsi",            // RSP    = user_rsp (top of the user stack page)
        "push {rflags}",       // RFLAGS = 0x202 (IF=1, reserved bit 1)
        "push rdx",            // CS     = user_cs (user code | RPL3)
        "push rdi",            // RIP    = user_rip (USER_CODE_VA)
        "iretq",
        rflags = const USER_RFLAGS,
        resume_sp = sym KERNEL_RESUME_SP,
    )
}

// ===========================================================================
// syscall_entry: ring3 `int 0x80` lands here in ring0 on the TSS RSP0 stack.
// (a) PRE: the user stub executed `int 0x80`; the CPU switched to TSS.RSP0 and
//     pushed [SS,RSP,RFLAGS,CS,RIP] (no error code — INT n pushes none); rax
//     holds the syscall arg. POST: the arg is handed to the Rust handler, then
//     a NON-LOCAL return reloads the kernel resume SP, pops the parked
//     callee-saved set and `ret`s into enter_ring3's caller. The RSP0 frame is
//     abandoned (reused on the next syscall).
// (b) ABI: targeted by a DPL=3 64-bit INTERRUPT gate (IF cleared on entry).
//     RSP0 is 16-aligned; the CPU pushed 5 qwords (40 bytes) → rsp%16==8, so
//     `sub rsp,8` re-establishes the SysV 16-alignment before the `call`.
//     Intel syntax (Rust default).
// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK").
// ===========================================================================
#[unsafe(naked)]
unsafe extern "C" fn syscall_entry() {
    naked_asm!(
        // rax = syscall arg (0xCAFE) → SysV arg0 for the Rust handler.
        "mov rdi, rax",
        // Re-align to 16 for the SysV call (rsp%16==8 after the CPU's 5 pushes).
        "sub rsp, 8",
        "call {handler}",
        // Non-local return into the kernel: drop the RSP0 frame, reload the
        // parked kernel SP, restore callee-saved, and `ret` to user_demo.
        "lea rax, [rip + {resume_sp}]",
        "mov rsp, [rax]",
        "pop r15",
        "pop r14",
        "pop r13",
        "pop r12",
        "pop rbp",
        "pop rbx",
        "ret",
        handler = sym x86_syscall_handler,
        resume_sp = sym KERNEL_RESUME_SP,
    )
}

/// The safe-ish kernel-side syscall handler (the ONLY Rust that observes the
/// trapped-back syscall). Records the arg, prints the proof line, and sets the
/// seen flag. Runs in ring0 on the TSS RSP0 stack; `serial_*` are the same
/// crate-root safe writers the rest of tb-hal uses.
extern "C" fn x86_syscall_handler(arg: u64) {
    SYSCALL_ARG.store(arg, Ordering::Release);
    SYSCALL_SEEN.store(true, Ordering::Release);
    crate::serial_write_str("syscall from user: arg=");
    write_hex_u64(arg);
    crate::serial_write_byte(b'\n');
}

// ---------------------------------------------------------------------------
// Safe M4 surface (re-exported through arch/mod.rs -> lib.rs).
// ---------------------------------------------------------------------------

/// Run the whole x86_64 ring0↔ring3 round trip and report success.
///
/// Sets up a ring3-accessible code + stack mapping, points the `int 0x80` IDT
/// gate at [`syscall_entry`] with DPL=3, drops to ring3 at the user stub, and
/// returns once the stub's syscall has trapped back and been handled. Returns
/// `true` iff the syscall was observed FROM ring3 carrying [`EXPECTED_ARG`]
/// (`0xCAFE`) — i.e. the full privileged/unprivileged split worked end-to-end.
///
/// Preconditions (met by `rust_main`'s ordering): `install_traps()` has run
/// (so the GDT carries the DPL3 user descriptors + a valid `TSS.RSP0`, and the
/// IDT is loaded) and `mmu_init()` has run (so `IA32_EFER.NXE` is set, making
/// the stack page's NX bit effective).
pub fn user_demo() -> bool {
    // 1. Map the ring3 code/stack pages (U/S=1 at every level) into live CR3.
    // SAFETY: ring 0, single vCPU, interrupts masked; see `map_user_pages`.
    unsafe {
        map_user_pages();
    }

    // 2. Open the syscall door: rewrite IDT vector 0x80 to a DPL=3 gate that
    //    targets `syscall_entry` (so `int 0x80` from ring3 is permitted).
    idt::set_user_gate(SYSCALL_VECTOR, syscall_entry as *const () as u64);

    // 3. (TSS.RSP0 is already programmed by `gdt::init`; nothing to do here.)

    // 4. Drop to ring3 at the stub. `enter_ring3` "returns" only via the
    //    syscall longjmp in `syscall_entry`.
    // SAFETY: the iret frame is fully formed — USER_CODE_VA/USER_STACK_TOP are
    // mapped U/S=1, and the selectors are the DPL3 user descriptors with RPL=3
    // (Intel SDM Vol.2 IRET inter-privilege checks: SS/CS RPL == 3 == their
    // DPL). Callee-saved state is parked + restored across the trip.
    unsafe {
        enter_ring3(
            USER_CODE_VA as u64,
            USER_STACK_TOP,
            (gdt::USER_CODE_SEL | 3) as u64,
            (gdt::USER_DATA_SEL | 3) as u64,
        );
    }

    // 5. Verdict: the syscall was observed from ring3 with the expected arg.
    SYSCALL_SEEN.load(Ordering::Acquire) && SYSCALL_ARG.load(Ordering::Acquire) == EXPECTED_ARG
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
/// Pure safe Rust (no `core::fmt`, no allocation), mirroring the kernel's own
/// helper so the proof line is self-contained inside tb-hal.
fn write_hex_u64(value: u64) {
    crate::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        crate::serial_write_byte(c);
        shift -= 4;
    }
}

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`,
//! `install_traps`, `breakpoint`) delegates to via `arch::mod`. ALL x86_64
//! `unsafe` and assembly is confined to this `arch::x86_64` subtree
//! (KERNEL-FOUNDATION-SPEC §1); every other crate is `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.
//! M1 adds CPU trap handling: `gdt` installs a permanent flat 64-bit GDT + TSS
//! (IST stacks), `idt` installs the 256-gate IDT, and `trap` holds the entry
//! thunks + the extern "C" handler that dispatches into safe Rust policy.
//! M2 adds the cooperative context switch: `sched` holds the naked
//! `ctx_switch` (saves/restores ONLY the psABI Fig. 3.4 callee-saved set
//! {rbx, rbp, r12-r15} + rsp, callee-saved-on-stack model) and the
//! initial-frame fabricator that tb-hal's shared `Task`/`task_create`/
//! `yield_to` layer builds on.
//! M3 adds the MMU layer: `mmu` holds the privileged paging-register
//! wrappers (read/write CR3, `invlpg`, CR4.PGE toggle, RDMSR/WRMSR for
//! IA32_EFER.NXE) plus the in-HAL `mmu_init`/`mmu_selftest` that splice a
//! new 4 KiB mapping at 0x4000_0000 into the LIVE boot page tables and
//! verify a remap with `invlpg`.
//! M4 adds the user/ring boundary: `user` holds the ring3 entry (`iretq`
//! into a ring3 stub via the DPL3 user GDT descriptors + a valid `TSS.RSP0`),
//! the DPL=3 `int 0x80` IDT gate, the ring0 syscall entry/handler, and the
//! `user_demo` round-trip that maps a `U/S=1` code+stack page through the M3
//! tables, drops to ring3, takes the stub's syscall and returns the verdict.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

// M1 trap stack: GDT/TSS, IDT, and the trap entry/dispatch asm + handler.
pub mod gdt;
pub mod idt;
pub mod trap;

// M2 cooperative switch: naked ctx_switch + new-task stack fabrication.
pub mod sched;

// M3 MMU: privileged paging-register wrappers (CR3, CR4.PGE, INVLPG,
// RDMSR/WRMSR for IA32_EFER.NXE) + the in-HAL 4 KiB map/remap self-test that
// splices a TEST_VA = 0x4000_0000 mapping into the live boot page tables.
pub mod mmu;

// M4 user/ring boundary: DPL3 user GDT descriptors + TSS.RSP0 (gdt.rs), the
// DPL=3 `int 0x80` gate (idt.rs), and HERE the ring3 stub, `iretq`-to-ring3
// entry, ring0 syscall entry/handler, and the `user_demo` round-trip that
// maps a U/S=1 code+stack page and drops to ring3.
pub mod user;

pub use serial::{serial_init, serial_write_byte};

// `breakpoint()` is re-exported as part of tb-hal's public trap surface; the
// `int3` lives in `trap.rs`. `set_trap_hook`/`TrapInfo`/`TrapKind`/`TrapAction`
// and the `dispatch_trap` glue live at the crate root (`lib.rs`).
pub use trap::breakpoint;

// M2: the arch-internal primitives consumed by the shared task layer in
// `lib.rs` (`Task`, `task_create`, `yield_to`). Per-arch contract:
//   * `unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize)`
//     — save the CURRENT task's callee-saved context on its own stack, store
//     the resulting SP to `*prev_sp_save`, adopt `next_sp` and resume the
//     next task (callee-saved-on-stack model, xv6 swtch.S shape).
//   * `fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize`
//     — fabricate a brand-new task's initial frame on `stack` so the FIRST
//     switch into it `ret`s into `entry`; returns the initial saved-SP handle
//     that `task_create` records for the first `yield_to`.
// (Same names + signatures as the aarch64 arm, so `arch/mod.rs` re-exports
// one uniform contract to `lib.rs`.)
pub use sched::{ctx_switch, task_stack_init};

// M3: the safe MMU surface, re-exported through `arch/mod.rs` so `lib.rs` can
// expose `tb_hal::mmu_init` / `tb_hal::mmu_selftest`. `mmu_init` programs
// IA32_EFER.NXE once after `install_traps`; `mmu_selftest` builds, proves and
// remaps the 4 KiB test mapping entirely inside tb-hal, returning pass/fail.
// (Same names + signatures as the aarch64 arm, one uniform contract.)
pub use mmu::{mmu_init, mmu_selftest};

// M4: the safe user/ring surface, re-exported through `arch/mod.rs` so `lib.rs`
// can expose `tb_hal::user_demo`. Drops to ring3, runs the stub's `int 0x80`,
// handles it in ring0 and returns whether the syscall was observed from user
// mode with the expected arg. (Same name + signature as the aarch64 arm.)
pub use user::user_demo;

use core::sync::atomic::{AtomicBool, Ordering};

/// Guards `install_traps()` so the permanent GDT/TSS/IDT are only built once
/// per vCPU even if it is called more than once.
static TRAPS_INSTALLED: AtomicBool = AtomicBool::new(false);

/// Install real CPU exception/interrupt handling: load the permanent GDT+TSS
/// (with IST stacks) FIRST, then the IDT (whose #DF/NMI/#MC gates reference
/// those IST stacks). Idempotent; called once from `rust_main` via
/// `tb_hal::install_traps()`.
pub fn install_traps() {
    if TRAPS_INSTALLED.swap(true, Ordering::SeqCst) {
        return;
    }
    // Order matters: the IDT's IST indices select TSS stacks the GDT installs.
    gdt::init();
    idt::init();
}

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, as the fatal
/// (`TrapAction::Halt`) trap terminator, and as the `#[panic_handler]`
/// fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     its markers; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! x86_64 permanent GDT + 64-bit TSS (Interrupt Stack Table) for `tb-hal`.
//!
//! Replaces the boot trampoline's transient GDT (`boot.rs`, `__boot_gdt64`) and
//! Firecracker's boot GDT with a PERMANENT flat 64-bit GDT plus a 64-bit TSS, so
//! the IDT (`idt.rs`) can route the double-fault, NMI and machine-check vectors
//! onto dedicated, known-good IST stacks. All `unsafe`/asm stays in `tb-hal`
//! (KERNEL-FOUNDATION-SPEC §1); the kernel crate is `#![forbid(unsafe_code)]`.
//!
//! Layout & descriptor bits are QUOTED from primary sources, not invented:
//!   * GDT segment descriptor — Access Byte (P,DPL,S,E,DC,RW,A) and Flags
//!     (G,DB,L): OSDev "Global Descriptor Table" == Intel SDM Vol.3A §3.4.5,
//!     Figure 3-8 "Segment Descriptor".
//!       - ring0 code : Access 0x9A (P=1,DPL=0,S=1,E=1,DC=0,RW=1,A=0); L=1.
//!       - ring0 data : Access 0x92 (P=1,DPL=0,S=1,E=0,DC=0,RW=1,A=0); DB=1.
//!   * 64-bit (Long Mode) TSS descriptor — 16 bytes, Access 0x89
//!     (P=1,DPL=0,S=0,Type=0x9 "64-bit TSS (Available)"), Base split across the
//!     low 8 bytes plus Base[63:32] in the high 8 bytes: OSDev "GDT" §"Long Mode
//!     System Segment Descriptor" == Intel SDM Vol.3A §7.2.3 / Figure 7-4
//!     "Format of TSS and LDT Descriptors in 64-Bit Mode".
//!   * 64-bit TSS body — RSP0..2, then IST1..7 (each a 64-bit stack pointer),
//!     then the 16-bit I/O-Map Base at byte 0x66; total 104 (0x68) bytes:
//!     OSDev "Task State Segment" §"Long Mode" == Intel SDM Vol.3A §7.7,
//!     Figure 7-11 "64-Bit TSS Format".

use core::arch::asm;
use core::mem::size_of;
use core::ptr::{addr_of, addr_of_mut};

/// GDT selectors: `index << 3 | TI(0) | RPL(0)`. Entry 1 = code, 2 = data,
/// 3..4 = the (16-byte) 64-bit TSS descriptor, 5 = ring3 user code,
/// 6 = ring3 user data (M4).
pub(super) const KERNEL_CODE_SEL: u16 = 0x08;
pub(super) const KERNEL_DATA_SEL: u16 = 0x10;
pub(super) const TSS_SEL: u16 = 0x18;

/// M4: ring3 user code selector — GDT index 5 (`5 << 3`). Callers OR in the
/// requested-privilege level (`| 3`) before loading it into CS for ring3.
pub(super) const USER_CODE_SEL: u16 = 0x28;
/// M4: ring3 user data selector — GDT index 6 (`6 << 3`). OR in `| 3` for the
/// ring3 SS/data segments.
pub(super) const USER_DATA_SEL: u16 = 0x30;

// Flat 64-bit descriptors (base 0, limit 0xFFFFF, page granularity). Base/limit
// are ignored by the CPU in 64-bit mode; the load-bearing bits are Access + L.
const NULL_DESC: u64 = 0x0000_0000_0000_0000;
const CODE_DESC: u64 = 0x00AF_9A00_0000_FFFF; // Access 0x9A, Flags G=1,L=1
const DATA_DESC: u64 = 0x00CF_9200_0000_FFFF; // Access 0x92, Flags G=1,DB=1

// M4 ring3 descriptors. Same flat shape as the ring0 pair but DPL=3 in the
// Access byte, so ring3 may load them (Intel SDM Vol.3A §3.4.5 Fig 3-8
// "Segment Descriptor"; §5.5/§5.8.1 privilege checks).
//   * user code: Access 0xFA (P=1,DPL=3,S=1,E=1,DC=0,RW=1,A=0); Flags G=1,L=1.
//   * user data: Access 0xF2 (P=1,DPL=3,S=1,E=0,DC=0,RW=1,A=0); Flags G=1,DB=1.
const USER_CODE_DESC: u64 = 0x00AF_FA00_0000_FFFF; // Access 0xFA, Flags G=1,L=1
const USER_DATA_DESC: u64 = 0x00CF_F200_0000_FFFF; // Access 0xF2, Flags G=1,DB=1

/// Access byte for an available 64-bit TSS descriptor: P=1, DPL=0, S=0,
/// Type=0x9 (Intel SDM Vol.3A §3.5, "64-bit TSS (Available)").
const TSS_ACCESS_AVAILABLE: u64 = 0x89;

/// Bytes per IST stack. 8 KiB is ample for the #DF / NMI / #MC handler chain
/// (handler + dispatch + hook + serial); multiple-of-16 keeps the top aligned.
const IST_STACK_SIZE: usize = 8 * 1024;

// 64-bit TSS as 26 dwords (104 bytes). Using u32 lanes (rather than a packed
// struct of u64s at 4-byte-aligned offsets) keeps every field naturally aligned
// so no `unaligned_references` hazard arises when we fill it through a pointer.
const TSS_DWORDS: usize = 26;
const TSS_RSP0: usize = 0x04 / 4; // 1   — RSP0 low dword (high is +1) [M4]
const TSS_IST1: usize = 0x24 / 4; // 9   — IST1 low dword (high is +1)
const TSS_IST2: usize = 0x2C / 4; // 11  — IST2
const TSS_IST3: usize = 0x34 / 4; // 13  — IST3
const TSS_IOPB: usize = 0x64 / 4; // 25  — I/O-Map Base lives in bits [31:16]

/// M4: bytes for the ring0 stack the CPU loads from `TSS.RSP0` on a ring3→ring0
/// privilege change (`int 0x80`). 16 KiB is ample for the syscall entry +
/// handler + serial; a multiple of 16 keeps the top 16-aligned.
const KERNEL_RSP0_SIZE: usize = 16 * 1024;

/// `lgdt`/`lidt` operand: 16-bit limit followed by the 64-bit linear base
/// (Intel SDM Vol.3A §2.4.1/§2.4.3; the m16&64 form). Packed = exactly 10 bytes.
#[repr(C, packed)]
pub(super) struct DescriptorPointer {
    pub(super) limit: u16,
    pub(super) base: u64,
}

#[repr(C)]
struct Tss {
    dwords: [u32; TSS_DWORDS],
}
impl Tss {
    const fn new() -> Self {
        Tss {
            dwords: [0; TSS_DWORDS],
        }
    }
}

#[repr(C, align(16))]
struct Gdt {
    // 7 entries: null(0), ring0 code(1), ring0 data(2), TSS lo/hi(3,4),
    // ring3 user code(5), ring3 user data(6) [M4].
    entries: [u64; 7],
}

#[repr(C, align(16))]
#[derive(Clone, Copy)]
struct IstStack([u8; IST_STACK_SIZE]);

/// M4: the dedicated ring0 stack `TSS.RSP0` points at. 16-aligned so its top is
/// 16-aligned (the CPU pushes the interrupt frame there on the `int 0x80` trap).
#[repr(C, align(16))]
struct KernelStack([u8; KERNEL_RSP0_SIZE]);

// Permanent tables. Zero-initialised, so they live in `.bss` (zeroed by
// `_start`); `init()` fills the live values at runtime through raw pointers.
static mut GDT: Gdt = Gdt { entries: [0; 7] };
static mut TSS: Tss = Tss::new();
static mut IST_STACKS: [IstStack; 3] = [IstStack([0; IST_STACK_SIZE]); 3];
// M4: the ring0 stack `TSS.RSP0` references (the ring3→ring0 trap landing).
static mut RSP0_STACK: KernelStack = KernelStack([0; KERNEL_RSP0_SIZE]);

/// Top-of-stack (highest, exclusive) address of IST stack `i` (0..3). Stacks
/// grow down; the array base is 16-aligned and each frame is a 16-multiple, so
/// the returned pointer is 16-aligned as the CPU expects.
unsafe fn ist_top(i: usize) -> u64 {
    let base = addr_of!(IST_STACKS) as u64;
    base + ((i + 1) * IST_STACK_SIZE) as u64
}

/// Build the two qwords of a 64-bit (Long Mode) TSS descriptor for `base`/
/// `limit`. Bit positions per Intel SDM Vol.3A Figure 7-4 / OSDev "GDT".
fn tss_descriptor(base: u64, limit: u32) -> (u64, u64) {
    let limit = limit as u64;
    let low = (limit & 0xFFFF)                       // Limit[15:0]
        | ((base & 0x00FF_FFFF) << 16)               // Base[23:0]
        | (TSS_ACCESS_AVAILABLE << 40)               // Access byte (0x89)
        | (((limit >> 16) & 0xF) << 48)              // Limit[19:16]
        // Flags nibble [55:52] = 0 (G=0 byte-granular, AVL=0)
        | (((base >> 24) & 0xFF) << 56); // Base[31:24]
    let high = (base >> 32) & 0xFFFF_FFFF; // Base[63:32]; high dword reserved (0)
    (low, high)
}

/// Install the permanent GDT + TSS: fill the IST tops, encode the TSS
/// descriptor at the runtime address of `TSS`, `lgdt`, reload CS + data
/// segments, and `ltr`. Called once from `super::install_traps()`.
pub(super) fn init() {
    unsafe {
        // 1. Fill the TSS: IST1..3 tops + disable the I/O permission bitmap
        //    (I/O-Map Base == sizeof(TSS) puts it past the segment limit).
        let tss = addr_of_mut!(TSS) as *mut u32;
        let s1 = ist_top(0);
        let s2 = ist_top(1);
        let s3 = ist_top(2);
        *tss.add(TSS_IST1) = s1 as u32;
        *tss.add(TSS_IST1 + 1) = (s1 >> 32) as u32;
        *tss.add(TSS_IST2) = s2 as u32;
        *tss.add(TSS_IST2 + 1) = (s2 >> 32) as u32;
        *tss.add(TSS_IST3) = s3 as u32;
        *tss.add(TSS_IST3 + 1) = (s3 >> 32) as u32;
        *tss.add(TSS_IOPB) = (size_of::<Tss>() as u32) << 16;

        // 1b. M4: program TSS.RSP0 — the ring0 stack the CPU loads on a
        //     ring3→ring0 privilege change (`int 0x80`). MUST be valid before
        //     any ring3 entry (Intel SDM Vol.3A §6.14.4 "Stack Switching";
        //     §7.7 Fig 7-11, RSP0 at TSS byte 0x04). Top is exclusive + 16-aligned.
        let rsp0 = addr_of!(RSP0_STACK) as u64 + KERNEL_RSP0_SIZE as u64;
        *tss.add(TSS_RSP0) = rsp0 as u32;
        *tss.add(TSS_RSP0 + 1) = (rsp0 >> 32) as u32;

        // 2. Build the GDT: null, code, data, TSS descriptor (2 entries), and
        //    the M4 ring3 user code/data descriptors (entries 5 and 6).
        let tss_base = addr_of!(TSS) as u64;
        let tss_limit = (size_of::<Tss>() - 1) as u32;
        let (tss_lo, tss_hi) = tss_descriptor(tss_base, tss_limit);
        let gdt = addr_of_mut!(GDT) as *mut u64;
        *gdt.add(0) = NULL_DESC;
        *gdt.add(1) = CODE_DESC;
        *gdt.add(2) = DATA_DESC;
        *gdt.add(3) = tss_lo;
        *gdt.add(4) = tss_hi;
        *gdt.add(5) = USER_CODE_DESC; // M4: ring3 user code (DPL=3, L=1)
        *gdt.add(6) = USER_DATA_DESC; // M4: ring3 user data (DPL=3)

        // 3. Load it and reload the segment registers / task register.
        let gdtr = DescriptorPointer {
            limit: (size_of::<Gdt>() - 1) as u16,
            base: addr_of!(GDT) as u64,
        };
        load_gdt_and_segments(addr_of!(gdtr));
    }
}

/// M4: update `TSS.RSP0` — the ring0 stack the CPU switches to on a ring3→ring0
/// privilege change (`int 0x80`). `init()` already programs a valid default
/// (the dedicated `RSP0_STACK`); this helper exists so a later caller can point
/// `RSP0` at a per-task kernel stack. Writes the two 32-bit halves through the
/// live TSS (Intel SDM Vol.3A §7.7 Fig 7-11, RSP0 at byte 0x04).
///
/// (a) PRE: GDT/TSS installed (`init()` ran). POST: `TSS.RSP0 == rsp0`.
/// (b) ABI: two naturally-aligned 32-bit stores through the live TSS; no asm,
///     no flags. Caller must pass a valid, 16-aligned ring0 stack TOP.
/// (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK" — the `int 0x80`
///     from ring3 lands on this stack).
#[allow(dead_code)] // `init()`'s default suffices for M4; helper kept per spec
pub(super) fn set_rsp0(rsp0: u64) {
    // SAFETY: ring 0; `TSS` is a tb-hal-owned `static`, and TSS_RSP0(+1) index
    // the RSP0 qword within its 104-byte body; written while IF=0 (no trap can
    // race the two stores).
    unsafe {
        let tss = addr_of_mut!(TSS) as *mut u32;
        *tss.add(TSS_RSP0) = rsp0 as u32;
        *tss.add(TSS_RSP0 + 1) = (rsp0 >> 32) as u32;
    }
}

/// `lgdt` the new table, far-return to reload CS with the ring0 code selector
/// (loading an L=1 CS under EFER.LME|CR0.PG keeps us in 64-bit mode), reload
/// the data segments, then `ltr` the TSS selector.
///
/// (a) PRE: 64-bit long mode, `gdtr` points at a valid `DescriptorPointer`
///     whose GDT has compatible 0x08 code / 0x10 data and a 0x18 64-bit TSS.
///     POST: CS=0x08, DS/ES/SS/FS/GS=0x10, TR=0x18 against the new GDT.
/// (b) ABI: Intel syntax (Rust default). Uses the stack (push/`retfq`, balanced
///     so RSP nets zero); clobbers segment regs + scratch regs + flags; reads
///     the descriptor from memory. Sources: Intel SDM Vol.3A §2.4.1 (lgdt),
///     §3.4.3/§5.8.1 (CS reload / far transfer), §7.3 `ltr`; OSDev GDT Tutorial.
/// (c) Tested by: kernel M1 sequence (a #BP must dispatch + resume afterwards).
#[inline]
unsafe fn load_gdt_and_segments(gdtr: *const DescriptorPointer) {
    asm!(
        "lgdt [{gdtr}]",
        // Reload CS via a far return to label 2: push CS, push target RIP, retfq.
        "push {code}",
        "lea {tmp}, [rip + 2f]",
        "push {tmp}",
        "retfq",
        "2:",
        // Reload the data/stack segment registers with the ring0 data selector.
        "mov ds, {data:x}",
        "mov es, {data:x}",
        "mov ss, {data:x}",
        "mov fs, {data:x}",
        "mov gs, {data:x}",
        // Load the task register with the TSS selector (activates the IST).
        "ltr {tss:x}",
        gdtr = in(reg) gdtr,
        code = in(reg) KERNEL_CODE_SEL as u64,
        data = in(reg) KERNEL_DATA_SEL as u64,
        tss  = in(reg) TSS_SEL as u64,
        tmp  = lateout(reg) _,
    );
}

//! x86_64 IDT: 256 64-bit interrupt-gate descriptors pointing at the per-vector
//! thunks in `trap.rs`. All `unsafe`/asm stays in `tb-hal`; the kernel crate is
//! `#![forbid(unsafe_code)]` (KERNEL-FOUNDATION-SPEC §1).
//!
//! Descriptor bits are QUOTED from primary sources, not invented:
//!   * 64-bit IDT gate descriptor — 16 bytes laid out offset_low(16) /
//!     selector(16) / ist(8, bits[2:0]) / type_attr(8) / offset_mid(16) /
//!     offset_high(32) / reserved(32); `type_attr = 0x8E` means P=1, DPL=0,
//!     Type=0xE "64-bit Interrupt Gate": OSDev "Interrupt Descriptor Table"
//!     §"Structure on x86-64" == Intel SDM Vol.3A §6.14.1, Figure 6-8
//!     "64-Bit IDT Gate Descriptors".
//!   * IST field selects a Task-State-Segment stack (0 = none); we route #DF
//!     (vector 8) -> IST1, NMI (2) -> IST2, #MC (18) -> IST3 onto the stacks set
//!     up in `gdt.rs`: Intel SDM Vol.3A §6.14.5 "Interrupt Stack Table".

use core::arch::asm;
use core::mem::size_of;
use core::ptr::{addr_of, addr_of_mut};

use super::gdt::{DescriptorPointer, KERNEL_CODE_SEL};
use super::trap;

/// One 64-bit IDT gate descriptor (16 bytes). Field order == on-wire layout.
#[repr(C)]
#[derive(Clone, Copy)]
#[allow(dead_code)] // fields are written, never read back by Rust
struct IdtEntry {
    offset_low: u16,
    selector: u16,
    ist: u8,
    type_attr: u8,
    offset_mid: u16,
    offset_high: u32,
    reserved: u32,
}
impl IdtEntry {
    const fn missing() -> Self {
        IdtEntry {
            offset_low: 0,
            selector: 0,
            ist: 0,
            type_attr: 0,
            offset_mid: 0,
            offset_high: 0,
            reserved: 0,
        }
    }

    /// Point this gate at `handler`, running on IST stack `ist` (0 = current
    /// stack). type_attr 0x8E == Present, DPL 0, 64-bit interrupt gate.
    fn set(&mut self, handler: u64, ist: u8) {
        self.offset_low = handler as u16;
        self.offset_mid = (handler >> 16) as u16;
        self.offset_high = (handler >> 32) as u32;
        self.selector = KERNEL_CODE_SEL;
        self.ist = ist & 0x7;
        self.type_attr = 0x8E;
        self.reserved = 0;
    }

    /// M4: point this gate at `handler` as a DPL=3 64-bit interrupt gate
    /// (type_attr 0xEE = P=1, DPL=3, Type=0xE), so an `int 0x80` issued from
    /// ring3 is permitted to invoke it — for a software interrupt the CPU
    /// requires `CPL <= gate DPL` (Intel SDM Vol.3A §6.12.1.2 "the processor
    /// checks that the CPL is less than or equal to the DPL of the [gate]";
    /// Fig 6-8 "64-Bit IDT Gate Descriptors"). The handler still runs in ring0
    /// via the ring0 code selector; no IST (current/TSS stack).
    fn set_user(&mut self, handler: u64) {
        self.offset_low = handler as u16;
        self.offset_mid = (handler >> 16) as u16;
        self.offset_high = (handler >> 32) as u32;
        self.selector = KERNEL_CODE_SEL;
        self.ist = 0;
        self.type_attr = 0xEE;
        self.reserved = 0;
    }
}

#[repr(C, align(16))]
struct Idt {
    entries: [IdtEntry; 256],
}

// Zero-initialised -> `.bss` (zeroed by `_start`); `init()` fills it at runtime.
static mut IDT: Idt = Idt {
    entries: [IdtEntry::missing(); 256],
};

/// Build all 256 gates from the `trap.rs` thunk table, route the IST-backed
/// vectors, then `lidt`. Called once from `super::install_traps()` AFTER the
/// GDT/TSS are live (the IST indices reference TSS stacks `gdt.rs` installs).
pub(super) fn init() {
    unsafe {
        let entries = addr_of_mut!(IDT) as *mut IdtEntry;
        let mut v = 0usize;
        while v < 256 {
            let ist = match v {
                8 => 1,  // #DF  -> IST1
                2 => 2,  // NMI  -> IST2
                18 => 3, // #MC  -> IST3
                _ => 0,  // everything else: current stack
            };
            let mut entry = IdtEntry::missing();
            entry.set(trap::thunk(v), ist);
            core::ptr::write(entries.add(v), entry);
            v += 1;
        }

        let idtr = DescriptorPointer {
            limit: (size_of::<[IdtEntry; 256]>() - 1) as u16, // 256*16 - 1 = 4095
            base: addr_of!(IDT) as u64,
        };
        // (a) PRE: `idtr` describes a 256-entry IDT. POST: IDTR loaded.
        // (b) ABI: `lidt m16&64`; reads memory (readonly), no stack, no flags.
        //     Intel SDM Vol.3A §2.4.3 / §6.10. Intel syntax (Rust default).
        // (c) Tested by: kernel M1 sequence (a #BP must vector through this IDT).
        asm!(
            "lidt [{}]",
            in(reg) addr_of!(idtr),
            options(readonly, nostack, preserves_flags),
        );
    }
}

/// M4: install a single DPL=3 64-bit interrupt gate at `vector`, pointing at
/// `handler`, by rewriting the already-loaded IDT IN PLACE. No `lidt` reload is
/// needed: the CPU re-reads the IDT from memory on every interrupt, and the
/// IDTR base is unchanged. Used so the ring3 user stub's `int 0x80` can trap
/// into tb-hal's `syscall_entry` (`user.rs`).
///
/// Replaces whatever `init()` put at `vector` (for 0x80 that was the generic
/// DPL=0 thunk, never used by M0–M3), so all earlier gates are untouched.
pub(super) fn set_user_gate(vector: usize, handler: u64) {
    // (a) PRE: `init()` ran (IDT built + `lidt`'d) and IF=0 (no interrupt can
    //     race this 16-byte write). POST: gate `vector` is a DPL=3 ring0
    //     interrupt gate targeting `handler`.
    // (b) ABI: a single `IdtEntry` structure store through the live IDT; no
    //     asm, no flags. `vector < 256` (caller passes 0x80).
    // (c) Tested by: scripts/run-x86_64.sh ("M4: user/ring OK").
    debug_assert!(vector < 256);
    // SAFETY: `IDT` is a tb-hal-owned `static`; `vector < 256` keeps the write
    // inside its 256-entry array; the write happens with interrupts masked, so
    // no half-written gate can be observed by a concurrent interrupt.
    unsafe {
        let entries = addr_of_mut!(IDT) as *mut IdtEntry;
        let mut entry = IdtEntry::missing();
        entry.set_user(handler);
        core::ptr::write(entries.add(vector), entry);
    }
}

//! aarch64 **M4 "user/ring boundary"**: drop to EL0, issue an `svc`, trap back
//! into EL1, prove the full round-trip (unit A-user).
//!
//! This is the aarch64 half of milestone **M4**. M0-M3 brought up serial, the
//! EL1 trap path, the cooperative context switch and the MMU (identity 1 GiB
//! blocks + a 4 KiB map/remap self-test under L1[2]). M4 demonstrates the
//! privileged/unprivileged split end-to-end:
//!
//!   1. Map a fresh **user code page** (`USER_CODE_VA`) and **user stack page**
//!      (`USER_STACK_VA`) with EL0 permissions, via a private L2->L3 chain hung
//!      under a previously-unused root slot **L1[3]** (VA 0xC000_0000, the 3 GiB
//!      line). We read the LIVE root out of `TTBR0_EL1` rather than touching
//!      `mmu.rs`'s private `ID_L1`, so this file stays self-contained.
//!   2. [`enter_el0`] saves the kernel's resume context, programs `SP_EL0` /
//!      `ELR_EL1` / `SPSR_EL1` and `eret`s down to **EL0t** at the user stub.
//!   3. The [`user_stub`] (a position-independent naked fn running at the
//!      aliased `USER_CODE_VA`) loads the magic arg `0xCAFE` into `x0` and
//!      executes `svc #0`.
//!   4. `svc` is taken back to **EL1h** through the **"Lower EL using AArch64,
//!      Synchronous"** vector slot, which `vectors.rs` now routes to the real
//!      trampoline `__vec_el0_sync` -> [`aarch64_el0_sync_handler`] (here).
//!      The handler confirms `ESR_EL1.EC == 0x15` (SVC from AArch64), records
//!      the arg, then **longjmps** straight back into [`enter_el0`]'s caller --
//!      it deliberately does NOT `eret` to EL0, so the kernel keeps control.
//!   5. [`user_demo`] reads the recorded flag/arg and returns `true` iff the
//!      syscall was observed from EL0 with the expected argument.
//!
//! Return strategy (the "simplest correct design" the M4 spec calls out): a
//! kernel-internal **setjmp/longjmp**. [`enter_el0`] stashes the AAPCS64
//! callee-saved registers + LR + SP of its caller into the static
//! [`KERNEL_RESUME`] buffer before the `eret`. The SVC handler, instead of
//! returning to EL0, reloads that buffer and `ret`s -- so from the caller's
//! point of view [`enter_el0`] simply "returned" once the syscall fired. The
//! kernel SP needs no explicit save/restore beyond this: taking the exception
//! to EL1h resumes on `SP_EL1`, which was never changed by the EL0 excursion
//! (EL0t runs on `SP_EL0`), so the 0x110 exception frame is pushed onto the
//! kernel stack and is harmlessly abandoned when SP is reset on the longjmp.
//!
//! ALL `unsafe` + asm lives here in tb-hal (framekernel rule); the kernel crate
//! stays `#![forbid(unsafe_code)]` and only branches on the returned `bool`.
//!
//! VERIFIED facts this module is built on (sources re-fetched 2026-06-07; do
//! NOT change the constants without re-reading them):
//!
//!  * **EL0 entry via `eret`.** `eret` returns to the EL and stack-pointer
//!    selected by `SPSR_EL1.M[4:0]`. `M = 0b00000` = **EL0t** (EL0, which always
//!    uses `SP_EL0`); `M[4]=0` selects AArch64. Source: Linux v6.6
//!    `arch/arm64/include/uapi/asm/ptrace.h` -- `PSR_MODE_EL0t 0x00000000`,
//!    `PSR_MODE_EL1h 0x00000005`, `PSR_F_BIT 0x40`, `PSR_I_BIT 0x80`,
//!    `PSR_A_BIT 0x100`, `PSR_D_BIT 0x200`; Arm ARM (DDI 0487) D1 "AArch64
//!    exception model" (`ERET` + `SPSR_ELx` PSTATE restore); osdev.org
//!    "AArch64 Exception Levels" (eret-to-EL0 recipe: set `SP_EL0`, `ELR_EL1`,
//!    `SPSR_EL1`, then `eret`). We use `SPSR_EL1 = 0x3C0` = EL0t with `DAIF`
//!    masked: there is no GIC/timer configured yet, so masking async exceptions
//!    at EL0 keeps parity with the kernel's masked state and avoids a stray
//!    IRQ/FIQ vectoring through an as-yet-stub Lower-EL slot. `svc` is a
//!    SYNCHRONOUS exception and is unaffected by `DAIF`.
//!  * **SVC syndrome.** A `svc` from AArch64 state sets `ESR_EL1.EC = 0x15`
//!    (bits[31:26]); the 16-bit immediate lands in `ESR_EL1.ISS[15:0]`. Source:
//!    Linux v6.6 `arch/arm64/include/asm/esr.h` -- `ESR_ELx_EC_SVC64 (0x15)`,
//!    `ESR_ELx_EC_SHIFT (26)`, `ESR_ELx_EC_MASK`; Arm ARM D17.2.37 "ESR_EL1".
//!  * **EL0-accessible descriptor bits** (VMSAv8-64 stage-1 L3 page). Source:
//!    Linux v6.6 `arch/arm64/include/asm/pgtable-hwdef.h` --
//!      - `PTE_TYPE_PAGE (3 << 0)`  : L3 leaf type.
//!      - `PTE_USER   (1 << 6)`  /* AP[1] */ : set => EL0 may access.
//!      - `PTE_RDONLY (1 << 7)`  /* AP[2] */ : clear => read/write.
//!        AP[2:1] = 0b01 (PTE_USER set, PTE_RDONLY clear) = EL1 RW + EL0 RW
//!        (Arm ARM D8 stage-1 AP[2:1] table; cross-checked vs Linux
//!        `_PAGE_SHARED`, which sets `PTE_USER` for user RW pages).
//!      - `PTE_SHARED (3 << 8)`  : SH[1:0] inner shareable.
//!      - `PTE_AF     (1 << 10)` : Access Flag -- MANDATORY on every leaf (no
//!        AF-fault handler installed; a cleared AF => abort on first access).
//!      - `PTE_PXN    (1 << 53)` : Privileged execute-never (set on user pages
//!        so EL1 cannot execute EL0 code -- defensive).
//!      - `PTE_UXN    (1 << 54)` : User (EL0) execute-never. CLEAR on the code
//!        page (EL0 must execute it); SET on the stack page (data only).
//!      - `PTE_ATTRINDX(t) ((t) << 2)` : AttrIndx. We use index 1 = Normal WB,
//!        matching the `MAIR_EL1` programmed by `mmu.rs::mmu_init` (attr0 =
//!        Device-nGnRnE, attr1 = Normal WB RA/WA).
//!    The identity RAM block (L1[1]) is `AP=0b00` (EL0 no access), which is why
//!    a FRESH EL0 mapping is required -- we cannot `eret` into kernel-image VAs.
//!  * **TTBR0_EL1 BADDR.** The live L1 table's physical base is `TTBR0_EL1`
//!    bits[47:1] (bit0 = CnP); for our 4 KiB-granule config the table is
//!    4 KiB-aligned, so `TTBR0_EL1 & 0x0000_FFFF_FFFF_F000` recovers it. The
//!    root sits in the identity-mapped RAM gigabyte, so its PA == its VA and it
//!    is directly writable. Source: Arm ARM D19.2 "TTBR0_EL1"; Linux v6.6
//!    `pgtable-hwdef.h` `TTBR_CNP_BIT (UL(1) << 0)`.
//!  * **First map needs no TLBI.** L1[3] was invalid (`.bss`-zeroed; `mmu_init`
//!    only set L1[0]/L1[1], the self-test set L1[2]); entries that fault are
//!    architecturally never cached, so publishing the new chain with
//!    `dsb ishst` + `isb` suffices (same rule the M3 first-map relied on).
//!    Arm ARM D8.14 / Linux `__flush_tlb_kernel_pgtable` discussion.
//!  * **AAPCS64 callee-saved set** (the longjmp save area): r19-r29 + SP, with
//!    r29 = FP and r30 = LR. Source: ARM-software/abi-aa `aapcs64.rst` §6.1.1.

use core::arch::{asm, naked_asm};
use core::cell::UnsafeCell;
use core::ptr::write_volatile;
use core::sync::atomic::{AtomicBool, AtomicU64, Ordering};

// ===========================================================================
// Virtual layout (a fresh, EL0-accessible window in the unused L1[3] gigabyte)
// ===========================================================================

/// User code page VA: 3 GiB (L1[3], L2[0], L3[0]). Page-aligned. Outside both
/// the identity map (L1[0]/L1[1]) and the M3 self-test region (L1[2]).
const USER_CODE_VA: u64 = 0xC000_0000;
/// User stack page VA: `USER_CODE_VA + 4 KiB` (L1[3], L2[0], L3[1]).
const USER_STACK_VA: u64 = 0xC000_1000;
/// Top of the (downward-growing) user stack: one page above its base.
const USER_STACK_TOP_VA: u64 = USER_STACK_VA + 0x1000;

/// Root (L1) index of the user window: VA[38:30].
const USER_L1_IDX: usize = ((USER_CODE_VA >> 30) & 0x1FF) as usize; // = 3
/// L3 index of the code page: VA[20:12].
const USER_CODE_L3_IDX: usize = ((USER_CODE_VA >> 12) & 0x1FF) as usize; // = 0
/// L3 index of the stack page: VA[20:12].
const USER_STACK_L3_IDX: usize = ((USER_STACK_VA >> 12) & 0x1FF) as usize; // = 1

// Layout locks: both pages must share L1[3] and L2[0], be page-aligned, and
// land on distinct L3 slots, or the single USER_L2/USER_L3 chain is wrong.
const _: () = assert!(USER_CODE_VA & 0xFFF == 0 && USER_STACK_VA & 0xFFF == 0);
const _: () = assert!(USER_L1_IDX == 3);
const _: () = assert!((USER_CODE_VA >> 30) & 0x1FF == (USER_STACK_VA >> 30) & 0x1FF);
const _: () = assert!((USER_CODE_VA >> 21) & 0x1FF == 0 && (USER_STACK_VA >> 21) & 0x1FF == 0);
const _: () = assert!(USER_CODE_L3_IDX == 0 && USER_STACK_L3_IDX == 1);

/// Magic syscall argument the user stub passes in `x0` (proves we ran at EL0).
const USER_SYSCALL_ARG: u64 = 0xCAFE;

// ===========================================================================
// VMSAv8-64 descriptor bits + EL0 leaf templates (verified -- module doc)
// ===========================================================================

const DESC_PAGE: u64 = 0b11; // L3 leaf type
const DESC_TABLE: u64 = 0b11; // table descriptor (L1/L2 -> next level)
const DESC_AF: u64 = 1 << 10; // Access Flag (mandatory)
const DESC_SH_INNER: u64 = 0b11 << 8; // SH[1:0] inner shareable
const DESC_ATTRINDX_NORMAL: u64 = 1 << 2; // AttrIndx = 1 -> MAIR attr1 (Normal WB)
const AP_EL0_RW: u64 = 1 << 6; // AP[1] (PTE_USER): EL1 RW + EL0 RW
const DESC_PXN: u64 = 1 << 53; // Privileged execute-never
const DESC_UXN: u64 = 1 << 54; // User (EL0) execute-never

/// User code leaf: Normal WB, EL0 RW, **EL0-executable** (UXN=0), EL1 no-exec.
const PAGE_USER_CODE: u64 =
    DESC_PAGE | DESC_AF | DESC_SH_INNER | DESC_ATTRINDX_NORMAL | AP_EL0_RW | DESC_PXN;
/// User stack leaf: Normal WB, EL0 RW, no-execute at either EL (UXN=1, PXN=1).
const PAGE_USER_STACK: u64 =
    DESC_PAGE | DESC_AF | DESC_SH_INNER | DESC_ATTRINDX_NORMAL | AP_EL0_RW | DESC_PXN | DESC_UXN;

/// `TTBR0_EL1` -> L1 base mask (bits[47:12]; drops CnP bit0 + RES0 low bits).
const TTBR_BADDR_MASK: u64 = 0x0000_FFFF_FFFF_F000;

// ===========================================================================
// ESR_EL1 classification + EL0 entry PSTATE (verified -- module doc)
// ===========================================================================

const ESR_EC_SHIFT: u64 = 26;
const ESR_EC_MASK: u64 = 0x3F;
const EC_SVC64: u64 = 0x15; // SVC instruction execution in AArch64 state

/// `SPSR_EL1` for the `eret` to EL0: M[4:0] = 0 (EL0t, AArch64) + D|A|I|F
/// masked (0x3C0). See module doc for the DAIF rationale.
const SPSR_EL0T_DAIF: u64 = 0x3C0;

// ===========================================================================
// Static tables, the user stack frame, and the kernel longjmp save area
// (all `.bss`, zeroed by `_start`; identity-mapped, so PA == VA)
// ===========================================================================

/// A 4096-aligned, page-sized cell used for the user L2/L3 tables and the user
/// stack frame. Mirrors `mmu.rs`'s `TableCell`/`Frame4K` but is local to this
/// module (those types are private to `mmu.rs`).
#[repr(C, align(4096))]
struct Page(UnsafeCell<[u64; 512]>);

// SAFETY: single-vCPU, cooperative kernel -- no concurrent mutator. All access
// goes through volatile raw-pointer helpers; no Rust reference to the interior
// is ever minted, so the `Sync` impl cannot be used to alias `&mut`.
unsafe impl Sync for Page {}

impl Page {
    /// A new all-zero (all-invalid) page; `const`, so it can sit in `.bss`.
    const fn new() -> Self {
        Page(UnsafeCell::new([0; 512]))
    }
    /// Physical address of this page (identity space: the pointer IS the PA).
    fn pa(&self) -> u64 {
        self.0.get() as u64
    }
}

/// Write one descriptor slot, volatile (the table walker reads behind the
/// compiler's back; ordinary stores could be reordered or elided).
fn page_set(p: &Page, idx: usize, desc: u64) {
    debug_assert!(idx < 512);
    // SAFETY: `p` is one of this module's static 4096-aligned `Page`s; the cell
    // is `#[repr(C, align(4096))]` over `[u64; 512]`, so casting to `*mut u64`
    // and offsetting by `idx < 512` stays in bounds and aligned. Single vCPU:
    // no concurrent CPU-side access; the walker is sequenced by the explicit
    // `dsb`s at the call sites in `user_demo`.
    unsafe { write_volatile((p.0.get() as *mut u64).add(idx), desc) }
}

/// L2 table for the user window (hung under root L1[3]; entry covers 2 MiB).
static USER_L2: Page = Page::new();
/// L3 table for the user window (hung under USER_L2[0]; entry covers 4 KiB).
static USER_L3: Page = Page::new();
/// The physical backing frame for the user stack page.
static USER_STACK_FRAME: Page = Page::new();

/// Kernel longjmp save area: x19..x28, x29(FP), x30(LR) at byte offsets
/// 0x00..0x58, then the kernel SP at 0x60 (13 words; padded to 16 for
/// alignment headroom). Written by [`enter_el0`], reloaded by the SVC handler.
#[repr(C, align(16))]
struct ResumeBuf(UnsafeCell<[u64; 16]>);

// SAFETY: as `Page` -- single vCPU, raw-pointer (asm) access only, no interior
// reference ever minted. Written exactly once per `enter_el0` call and read
// exactly once on the matching SVC longjmp, with no interleaving.
unsafe impl Sync for ResumeBuf {}

static KERNEL_RESUME: ResumeBuf = ResumeBuf(UnsafeCell::new([0; 16]));

/// Set true by the SVC handler when it observes the `svc` from EL0.
static SYSCALL_SEEN: AtomicBool = AtomicBool::new(false);
/// The `x0` argument captured from the EL0 `svc` (expected `0xCAFE`).
static SYSCALL_ARG: AtomicU64 = AtomicU64::new(0);

// ===========================================================================
// Privileged system-register / barrier wrappers (asm confined here)
// ===========================================================================

// -- read_ttbr0_el1() --------------------------------------------------------
// (a) PRE : EL1, MMU live (post `mmu_init`). POST: returns the raw TTBR0_EL1.
// (b) ABI : one `mrs`; no memory, no stack, NZCV preserved.
// (c) TEST: `user_demo` masks the result to find the live L1 root.
fn read_ttbr0_el1() -> u64 {
    let v: u64;
    // SAFETY: TTBR0_EL1 is an EL1-readable system register; `mrs` has no memory
    // or stack effect and leaves NZCV unchanged. We run at EL1.
    unsafe {
        asm!("mrs {0}, ttbr0_el1", out(reg) v, options(nomem, nostack, preserves_flags));
    }
    v
}

// -- read_esr_el1() ----------------------------------------------------------
// (a) PRE : in the SVC handler, before any nested exception. POST: returns the
//           syndrome of the `svc` (EC == 0x15).
// (b) ABI : one `mrs`; no memory, no stack, NZCV preserved.
// (c) TEST: the handler asserts `EC == EC_SVC64` before recording the arg.
fn read_esr_el1() -> u64 {
    let v: u64;
    // SAFETY: ESR_EL1 is an EL1-readable system register; side-effect-free load.
    unsafe {
        asm!("mrs {0}, esr_el1", out(reg) v, options(nomem, nostack, preserves_flags));
    }
    v
}

// -- dsb_ishst() / isb() -----------------------------------------------------
// Publish-store barrier and pipeline resync used when splicing the new user
// chain into the live root (same sequencing rule as `mmu.rs`).
fn dsb_ishst() {
    // SAFETY: a barrier is side-effect-free synchronization, always legal at EL1.
    unsafe { asm!("dsb ishst", options(nostack, preserves_flags)) }
}
fn isb() {
    // SAFETY: as `dsb_ishst`.
    unsafe { asm!("isb", options(nostack, preserves_flags)) }
}

/// Write a `u64` as a fixed-width `0x…` 16-hex-digit string over serial. Pure
/// safe Rust over the tb-hal byte writer (no `core::fmt`, no allocation).
fn write_hex_u64(value: u64) {
    crate::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        crate::serial_write_byte(c);
        shift -= 4;
    }
}

// ===========================================================================
// Exception frame mirror (must match `vectors.rs` SAVE_CONTEXT, exactly as in
// `trap.rs`): x0..x30 @ 0x00..0xF0, ELR_EL1 @ 0xF8, SPSR_EL1 @ 0x100, 0x110 B.
// We only read x0 (the syscall arg), but the full struct documents + locks the
// layout the trampoline hands us.
// ===========================================================================
#[repr(C)]
#[allow(dead_code)] // elr/spsr/_pad are part of the ABI but unread here
struct Frame {
    /// x0..x30 (x30 = LR), offsets 0x00..0xF0. `gpr[0]` carries the `svc` arg.
    gpr: [u64; 31],
    /// ELR_EL1 (the EL0 return address) at exception entry, offset 0xF8.
    elr: u64,
    /// SPSR_EL1 (the EL0 PSTATE) at exception entry, offset 0x100.
    spsr: u64,
    /// Alignment pad; frame size is 0x110 (16-aligned).
    _pad: u64,
}
const _: () = assert!(core::mem::size_of::<Frame>() == 0x110);
const _: () = assert!(core::mem::offset_of!(Frame, gpr) == 0x00);
const _: () = assert!(core::mem::offset_of!(Frame, elr) == 0xF8);
const _: () = assert!(core::mem::offset_of!(Frame, spsr) == 0x100);

// ===========================================================================
// The user stub: a position-independent EL0 payload (runs at USER_CODE_VA)
// ===========================================================================
// (a) PRE : reached only by the `eret` in `enter_el0`, executing at EL0t with
//           SP_EL0 = USER_STACK_TOP_VA and the page mapped EL0-RW + executable
//           (UXN=0). POST: traps to EL1 via `svc #0` with x0 = 0xCAFE; never
//           runs past the `svc` (the kernel keeps control and does not return).
// (b) ABI : `#[unsafe(naked)]` -- the body is EXACTLY these three instructions,
//           all PC-relative / immediate (no absolute relocation), so it is
//           valid at the aliased USER_CODE_VA. `mov x0,#0xcafe` is a single
//           MOVZ (0xCAFE fits in 16 bits). The target has no BTI, so no `bti`
//           landing pad is inserted.
// (c) TEST: scripts/run-aarch64.sh -- the handler prints
//           "syscall from user: arg=0x...cafe" and the kernel prints
//           "M4: user/ring OK".
/// The unprivileged (EL0) test payload: pass `0xCAFE` and `svc #0`, then spin.
#[unsafe(naked)]
extern "C" fn user_stub() -> ! {
    naked_asm!(
        "mov x0, #0xcafe", // magic arg in x0 (preserved across svc)
        "svc #0",          // synchronous trap to EL1 (ESR_EL1.EC = 0x15)
        "1: b 1b",         // unreachable: the kernel never returns to EL0
    )
}

// ===========================================================================
// enter_el0: kernel setjmp + drop to EL0 via eret
// ===========================================================================
// (a) PRE : EL1h, MMU live, the user code/stack pages mapped (USER_CODE_VA /
//           USER_STACK_VA). x0 = entry VA (USER_CODE_VA | code-offset), x1 =
//           user stack top. POST: the caller's AAPCS64 callee-saved regs + LR
//           + SP are saved in KERNEL_RESUME, then `eret` enters EL0t at x0 with
//           SP_EL0 = x1 and DAIF masked. Control "returns" to the caller ONLY
//           later, via the SVC handler's longjmp (which reloads KERNEL_RESUME).
// (b) ABI : `#[unsafe(naked)]`. Inputs x0/x1 (AAPCS64 arg0/arg1). Uses only x9
//           /x10 as scratch before the eret; x19..x30 are stored unmodified.
//           SP_EL1 is unchanged by the eret (EL0t runs on SP_EL0), so the
//           kernel stack is intact when the `svc` re-enters EL1h.
// (c) TEST: scripts/run-aarch64.sh -- the round-trip completes and
//           `user_demo` returns true.
/// Save the kernel resume context and `eret` down to EL0 at `entry_va` with
/// `SP_EL0 = stack_top`. Appears to "return" to its caller once the EL0 `svc`
/// is handled (the SVC handler longjmps back through [`KERNEL_RESUME`]).
#[unsafe(naked)]
extern "C" fn enter_el0(entry_va: u64, stack_top: u64) {
    naked_asm!(
        // -- setjmp: stash callee-saved + LR + SP into KERNEL_RESUME ---------
        "adrp x9, {save}",
        "add  x9, x9, :lo12:{save}",
        "mov  x10, sp",
        "stp  x19, x20, [x9, #0x00]",
        "stp  x21, x22, [x9, #0x10]",
        "stp  x23, x24, [x9, #0x20]",
        "stp  x25, x26, [x9, #0x30]",
        "stp  x27, x28, [x9, #0x40]",
        "stp  x29, x30, [x9, #0x50]", // FP + LR (caller's resume address)
        "str  x10,      [x9, #0x60]", // kernel SP
        // -- program the EL0 entry and drop privilege -----------------------
        "msr  sp_el0, x1",            // user stack top
        "msr  elr_el1, x0",           // user code entry VA
        "mov  x10, #0x3c0",           // SPSR_EL1 = EL0t (M=0) + DAIF masked
        "msr  spsr_el1, x10",
        "isb",                        // ensure ELR/SPSR/SP_EL0 are visible
        "eret",                       // -> EL0t at USER_CODE_VA
        save = sym KERNEL_RESUME,
    )
}

// ===========================================================================
// aarch64_el0_sync_handler: the real "Lower EL using AArch64, Synchronous"
// handler (called by vectors.rs `__vec_el0_sync` after SAVE_CONTEXT)
// ===========================================================================
// (a) PRE : entered at EL1h from the EL0 synchronous vector; x0 = &Frame (the
//           0x110 SAVE_CONTEXT frame on the kernel stack); ESR_EL1 still holds
//           the `svc` syndrome. POST: never returns normally -- records the
//           syscall (if EC == 0x15) and longjmps back into `enter_el0`'s caller
//           via KERNEL_RESUME. The EL0 context (ELR/SPSR/SP_EL0) is abandoned.
// (b) ABI : `extern "C"`, `#[no_mangle]` so the vector trampoline can `bl` it.
//           `-> !`: the trailing `asm!(options(noreturn))` restores x19..x30 +
//           SP and `ret`s to the saved LR. x9 is scratch (caller-saved).
// (c) TEST: scripts/run-aarch64.sh -- prints "syscall from user: arg=0x...cafe"
//           and the kernel reports "M4: user/ring OK".
/// EL0 synchronous handler: record the `svc` argument, then longjmp back into
/// the kernel (the milestone deliberately does NOT resume EL0).
#[no_mangle]
pub extern "C" fn aarch64_el0_sync_handler(frame: *const Frame) -> ! {
    // SAFETY: `frame` is `sp` immediately after the trampoline's 0x110-byte
    // SAVE_CONTEXT push -- a fully-initialised, 16-aligned `Frame` on the
    // kernel (SP_EL1) stack, live for this whole call. Single core, with
    // interrupts masked while we run, so we are the only accessor.
    let frame = unsafe { &*frame };

    let esr = read_esr_el1();
    let ec = (esr >> ESR_EC_SHIFT) & ESR_EC_MASK;

    if ec == EC_SVC64 {
        // x0 of the trapping EL0 context = the syscall argument.
        let arg = frame.gpr[0];
        SYSCALL_ARG.store(arg, Ordering::Release);
        SYSCALL_SEEN.store(true, Ordering::Release);
        crate::serial_write_str("syscall from user: arg=");
        write_hex_u64(arg);
        crate::serial_write_byte(b'\n');
    } else {
        // Any other synchronous exception from EL0 (e.g. an instruction/data
        // abort if the user mapping were wrong) is unexpected. Report it and
        // still longjmp back -- `user_demo` then sees SYSCALL_SEEN == false and
        // returns false, rather than wedging the core.
        crate::serial_write_str("user-test: unexpected EL0 sync, esr=");
        write_hex_u64(esr);
        crate::serial_write_byte(b'\n');
    }

    // -- longjmp: abandon the EL0 context, reload KERNEL_RESUME, `ret` into
    //    enter_el0's caller (as if enter_el0 had returned). After the SP
    //    reset, the exception frame + this handler's frame are discarded.
    // SAFETY: KERNEL_RESUME was just written by `enter_el0` (this call is the
    // matching pop). We restore exactly the AAPCS64 callee-saved set + SP it
    // saved and branch to the saved LR. `noreturn`: control never falls
    // through, so the abandoned frames below the restored SP are inert.
    unsafe {
        asm!(
            "adrp x9, {save}",
            "add  x9, x9, :lo12:{save}",
            "ldp  x19, x20, [x9, #0x00]",
            "ldp  x21, x22, [x9, #0x10]",
            "ldp  x23, x24, [x9, #0x20]",
            "ldp  x25, x26, [x9, #0x30]",
            "ldp  x27, x28, [x9, #0x40]",
            "ldp  x29, x30, [x9, #0x50]", // FP + LR (the kernel resume address)
            "ldr  x9,  [x9, #0x60]",      // kernel SP
            "mov  sp, x9",
            "ret",                        // -> enter_el0's caller (user_demo)
            save = sym KERNEL_RESUME,
            options(noreturn),
        )
    }
}

// ===========================================================================
// user_demo: the whole aarch64 M4 round-trip (the safe public surface)
// ===========================================================================
// (a) PRE : called once from `rust_main` AFTER mmu_init()/mmu_selftest() and
//           install_traps() (the MMU is live and the EL0 vector slot is armed).
//           POST: USER_CODE_VA/USER_STACK_VA are mapped EL0-accessible; the CPU
//           dropped to EL0, ran the stub, trapped back via `svc`, and the
//           kernel resumed here. Returns true iff the syscall was observed from
//           EL0 with arg == 0xCAFE.
// (b) ABI : plain safe function; all asm confined to the helpers/naked fns
//           above, so the `#![forbid(unsafe_code)]` kernel only sees a `bool`.
// (c) TEST: scripts/run-aarch64.sh -- "M4: user/ring OK" iff this returns true.
/// Map an EL0 code+stack page, drop to EL0 at a tiny stub that issues one
/// `svc`, handle it in the kernel, and prove the round-trip. `true` = pass.
pub fn user_demo() -> bool {
    // (1) Resolve the stub's physical (identity) address and split it into a
    //     page base + in-page offset. The stub is in `.text` (identity-mapped
    //     Normal WB under L1[1]), so its VA == PA.
    let stub_pa = user_stub as usize as u64;
    let code_page_pa = stub_pa & !0xFFF;
    let code_offset = stub_pa & 0xFFF;
    let entry_va = USER_CODE_VA | code_offset;

    // (2) Build the L3 leaves: code (EL0 RW + executable) and stack (EL0 RW,
    //     no-execute), then hang L3 under our L2[0]. Publish before linking the
    //     chain into the live root so the walker never sees it half-built.
    page_set(&USER_L3, USER_CODE_L3_IDX, code_page_pa | PAGE_USER_CODE);
    page_set(&USER_L3, USER_STACK_L3_IDX, USER_STACK_FRAME.pa() | PAGE_USER_STACK);
    page_set(&USER_L2, 0, USER_L3.pa() | DESC_TABLE);
    dsb_ishst();

    // (3) Plug our L2 into the LIVE root at L1[3] (read out of TTBR0_EL1 -- no
    //     dependency on mmu.rs's private ID_L1). L1[3] was invalid, so a first
    //     map needs no TLBI; publish + resync the pipeline.
    let l1 = (read_ttbr0_el1() & TTBR_BADDR_MASK) as *mut u64;
    // SAFETY: `l1` is the physical base of the live L1 table, which lives in the
    // identity-mapped RAM gigabyte (so PA == VA, directly writable) and has 512
    // 8-byte entries; USER_L1_IDX = 3 is in bounds. Single vCPU; the walker is
    // sequenced by the surrounding `dsb ishst`/`isb`.
    unsafe { write_volatile(l1.add(USER_L1_IDX), USER_L2.pa() | DESC_TABLE) };
    dsb_ishst();
    isb();

    // (4) Arm the result cells, then drop to EL0 at the stub. The SVC handler
    //     records the arg and longjmps back here (enter_el0 "returns").
    SYSCALL_SEEN.store(false, Ordering::Release);
    SYSCALL_ARG.store(0, Ordering::Release);
    enter_el0(entry_va, USER_STACK_TOP_VA);

    // (5) Verdict: the `svc` must have been observed from EL0 with arg 0xCAFE.
    SYSCALL_SEEN.load(Ordering::Acquire) && SYSCALL_ARG.load(Ordering::Acquire) == USER_SYSCALL_ARG
}

//! aarch64 backend for the `tb-hal` foundation crate.
//!
//! One of the two `#[cfg(target_arch)]` arms re-exported by `arch/mod.rs`. It
//! exposes the aarch64 primitives the safe `tb-hal` public API (`lib.rs`)
//! delegates to: [`serial_init`], [`serial_write_byte`], [`halt`] (M0), the
//! M1 trap surface [`install_traps`] and [`breakpoint`], the M2
//! cooperative-scheduling primitives [`ctx_switch`] and [`task_stack_init`]
//! (backing `lib.rs`'s safe `Task` / `task_create` / `yield_to`), the M3
//! MMU surface [`mmu_init`] / [`mmu_selftest`] (cold stage-1 bring-up +
//! 4 KiB map / Break-Before-Make remap self-test), and the M4 user/ring
//! surface [`user_demo`] (drop to EL0, `svc`, trap back into EL1).
//! (`serial_write_str` is composed in `lib.rs` from `serial_write_byte`, so it
//! is arch-independent.)
//!
//! Boot contract for the M0/M1 QEMU `virt` path (verified facts,
//! KERNEL-FOUNDATION-SPEC SS2): the vCPU enters `_start` at **EL1h, MMU OFF,
//! DAIF masked**, with **x0 = FDT/DTB pointer** (AAPCS64 arg0 already).
//! `boot.rs` owns that entry; `serial.rs` owns the PL011 UART; `vectors.rs`
//! owns the `VBAR_EL1` table; `trap.rs` owns the Rust trap dispatch;
//! `sched.rs` owns the M2 context switch (callee-saved x19..x30 + SP) and the
//! new-task initial-frame fabrication (x30 = entry); `mmu.rs` owns the M3
//! cold MMU bring-up (the MMU stays OFF until `rust_main` calls
//! [`mmu_init`] -- identity 1 GiB blocks: Device @ 0 covering the PL011,
//! Normal WB @ 0x4000_0000 covering RAM); `user.rs` owns the M4 EL0 excursion
//! (the EL0 entry/exit asm + the user-page mapping + the round-trip
//! [`user_demo`]). `vectors.rs`'s "Lower EL using AArch64, Synchronous" slot is
//! now a REAL handler (`__vec_el0_sync` -> `aarch64_el0_sync_handler` in
//! `user.rs`); the rest of the Lower-EL quadrant remains a fatal stub.

mod boot; // _start; arms VBAR_EL1; pure side-effect (`global_asm!`) module.
mod mmu; // M3: cold MMU bring-up + 4 KiB map / BBM remap self-test.
mod sched; // M2: ctx_switch (x19..x30 + SP) + initial-frame fabrication.
mod serial; // PL011 @ 0x0900_0000 (QEMU `virt` UART0).
mod trap; // Rust trap dispatch + breakpoint(); the only raw-frame deref.
mod user; // M4: EL0 entry/exit + user-page mapping + user_demo round-trip.
mod vectors; // VBAR_EL1 table + entry/exit stubs; pure `global_asm!` module.

pub use mmu::{mmu_init, mmu_selftest};
pub use sched::{ctx_switch, task_stack_init};
pub use serial::{serial_init, serial_write_byte};
pub use trap::breakpoint;
pub use user::user_demo;

// -- install_traps() --------------------------------------------------------
// (a) PRE : called once from rust_main, after serial_init, at EL1h. POST:
//           VBAR_EL1 == &__exception_vectors (the 2 KiB-aligned table in
//           vectors.rs) and an `isb` has made the new vector base
//           architecturally visible. Idempotent: `_start` already pre-armed the
//           very same table, so a second call just re-writes the same value.
// (b) ABI : clobbers one scratch x-register; touches no memory/stack; takes no
//           args. Arm ARM D19.2 requires a context-synchronisation event after
//           writing VBAR_EL1 before relying on it -- the `isb` provides it.
// (c) TEST: scripts/run-aarch64.sh -- after install, breakpoint() is caught,
//           the hook resumes, and the kernel prints "M1: traps OK".
/// Install the EL1 exception vectors (`VBAR_EL1`). Idempotent; call once.
pub fn install_traps() {
    // SAFETY: writing VBAR_EL1 is legal at EL1 and merely (re)selects our own
    // 2 KiB-aligned vector table (`vectors.rs`); `adrp/add :lo12:` form its
    // address with no memory access, and `isb` synchronises the change.
    unsafe {
        core::arch::asm!(
            "adrp {t}, __exception_vectors",
            "add  {t}, {t}, :lo12:__exception_vectors",
            "msr  vbar_el1, {t}",
            "isb",
            t = out(reg) _,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- halt() -----------------------------------------------------------------
// (a) PRE : any state; called on the M0/M1 happy path after the marker is
//           flushed, from the kernel #[panic_handler], and from the trap
//           handler's fatal (Halt) path. POST: never returns -- the vCPU is
//           parked in a low-power wait, re-parking on any wake event.
// (b) ABI : `wfi` clobbers nothing, touches no memory/stack, preserves NZCV.
// (c) TEST: scripts/run-aarch64.sh -- the kernel reaches here after printing
//           "M1: traps OK"; the runner times out and asserts the marker.
/// Halt the current vCPU forever (low-power wait loop).
pub fn halt() -> ! {
    loop {
        // SAFETY: `wfi` is an unprivileged hint with no memory or stack
        // effects; it is always legal at EL1 and merely suspends the core
        // until a wake event, after which we loop and re-park.
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 EL1 exception vector table (`VBAR_EL1`) and the trap entry/exit path.
//!
//! This is unit **A4 / milestone M1** on aarch64 (extended at **M4**). Like
//! `boot.rs` it is compiled purely for its `global_asm!` side effects: nothing
//! here is referenced from Rust except by symbol -- the table label
//! `__exception_vectors` (loaded into `VBAR_EL1` by `boot.rs::_start` and
//! re-armed by `mod.rs::install_traps`), the extern `aarch64_trap_handler`
//! (defined in `trap.rs`, M1), and the extern `aarch64_el0_sync_handler`
//! (defined in `user.rs`, M4). The linker keeps the whole table via
//! `KEEP(*(.text._vectors))` in `kernel/linker/aarch64.ld`.
//!
//! Layout (verified facts -- obey exactly):
//!  * `VBAR_EL1` points at a **2 KiB-aligned** table of **16 entries x 128 B**.
//!    The 16 slots are, in order, the cross product
//!    {Current-EL-SP0, Current-EL-SPx, Lower-EL-AArch64, Lower-EL-AArch32}
//!    x {Synchronous, IRQ/vIRQ, FIQ/vFIQ, SError/vSError}.
//!      - Arm Architecture Reference Manual (DDI 0487), D1 "AArch64 Exception
//!        model" / "Exception vectors" (the VBAR_ELx + 16x0x80 table).
//!      - OSDev Wiki, "Exception handling in AArch64" (vector table base must be
//!        2 KiB aligned; each of the 16 entries is 0x80 bytes).
//!      - Cross-checked against Linux `arch/arm64/kernel/entry.S`:
//!        `SYM_CODE_START(vectors)` is `.align 11` (2^11 = 2 KiB) and each
//!        `kernel_ventry` is `.align 7` (2^7 = 128 B); the ventry order is
//!        EL1t{sync,irq,fiq,err}, EL1h{sync,irq,fiq,err}, EL0_64{...}, EL0_32{...}.
//!  * The kernel boots and runs at **EL1h** (handler, `SP_EL1` == "SPx"), so a
//!    synchronous exception from our own code -- e.g. `brk #0` -- is taken
//!    through the **"Current EL with SPx, Synchronous"** slot: index 4, byte
//!    offset **0x200** (M1, real handler -> `trap.rs`).
//!  * A synchronous exception from **EL0** -- e.g. the M4 user stub's `svc #0`
//!    -- is taken through the **"Lower EL using AArch64, Synchronous"** slot:
//!    index 8, byte offset **0x400**. M4 makes this a REAL handler
//!    (`__vec_el0_sync` -> `aarch64_el0_sync_handler` in `user.rs`). Every
//!    OTHER slot still routes to the common stub (`__vec_other`), reported as
//!    `TrapKind::Other` (the default policy then halts).
//!  * Save / restore mirrors Linux `entry.S` `kernel_entry` / `kernel_exit`:
//!    push x0..x30 + `ELR_EL1` + `SPSR_EL1`; `mov x0, sp`; `bl` into Rust;
//!    reload `ELR_EL1`/`SPSR_EL1` (the handler may have advanced `ELR_EL1` by 4
//!    to resume past a `brk`); pop x0..x30; `eret`.
//!  * The target spec `targets/aarch64-tabos-none.json` is `abi: softfloat`
//!    with `-fp-armv8,-neon`, so the V/SIMD registers carry no live state and
//!    are intentionally NOT part of the frame (FP context save lands with
//!    preemption / userspace FP, not M1/M4).

use core::arch::global_asm;

// -- __exception_vectors + trap entry/exit ----------------------------------
// (a) PRE : VBAR_EL1 == &__exception_vectors (2 KiB aligned); a synchronous
//           exception is taken at Current-EL-SPx (M1) or Lower-EL-AArch64 (M4).
//           POST: a TrapFrame of x0..x30 + ELR_EL1 + SPSR_EL1 is built on the
//           exception stack (SP_EL1 -- the kernel stack), Rust dispatch runs,
//           then for the EL1 path state is restored and `eret` resumes the
//           interrupted context; for the EL0 SVC path the handler longjmps
//           into the kernel instead (see user.rs) and never returns here.
// (b) ABI  : SP must be 16-aligned on entry (kernel maintains it); the 0x110
//           frame keeps it aligned across `bl` (AAPCS64 arg0 = x0 = &TrapFrame,
//           arg1 = x1 = source tag). `bl` clobbers x30, which was already
//           saved. `eret` restores PSTATE from SPSR_EL1.
// (c) TEST : scripts/run-aarch64.sh -- breakpoint() takes slot 0x200 ("M1:
//           traps OK"); the user stub's `svc` takes slot 0x400 ("M4: user/ring
//           OK").
global_asm!(
    r#"
    // ---- context save: x0..x30, ELR_EL1, SPSR_EL1 -> 0x110-byte TrapFrame ----
    .macro SAVE_CONTEXT
    sub  sp, sp, #0x110
    stp  x0,  x1,  [sp, #0x00]
    stp  x2,  x3,  [sp, #0x10]
    stp  x4,  x5,  [sp, #0x20]
    stp  x6,  x7,  [sp, #0x30]
    stp  x8,  x9,  [sp, #0x40]
    stp  x10, x11, [sp, #0x50]
    stp  x12, x13, [sp, #0x60]
    stp  x14, x15, [sp, #0x70]
    stp  x16, x17, [sp, #0x80]
    stp  x18, x19, [sp, #0x90]
    stp  x20, x21, [sp, #0xA0]
    stp  x22, x23, [sp, #0xB0]
    stp  x24, x25, [sp, #0xC0]
    stp  x26, x27, [sp, #0xD0]
    stp  x28, x29, [sp, #0xE0]
    str  x30,      [sp, #0xF0]
    mrs  x9,  elr_el1            // x9/x10 already saved above; free to reuse
    mrs  x10, spsr_el1
    stp  x9,  x10, [sp, #0xF8]   // elr @ 0xF8, spsr @ 0x100
    .endm

    // ---- context restore (elr/spsr first, then GPRs reclaim x9/x10) ----------
    .macro RESTORE_CONTEXT
    ldp  x9,  x10, [sp, #0xF8]   // handler may have written elr (brk resume)
    msr  elr_el1,  x9
    msr  spsr_el1, x10
    ldp  x0,  x1,  [sp, #0x00]
    ldp  x2,  x3,  [sp, #0x10]
    ldp  x4,  x5,  [sp, #0x20]
    ldp  x6,  x7,  [sp, #0x30]
    ldp  x8,  x9,  [sp, #0x40]   // restores the real x9
    ldp  x10, x11, [sp, #0x50]   // restores the real x10
    ldp  x12, x13, [sp, #0x60]
    ldp  x14, x15, [sp, #0x70]
    ldp  x16, x17, [sp, #0x80]
    ldp  x18, x19, [sp, #0x90]
    ldp  x20, x21, [sp, #0xA0]
    ldp  x22, x23, [sp, #0xB0]
    ldp  x24, x25, [sp, #0xC0]
    ldp  x26, x27, [sp, #0xD0]
    ldp  x28, x29, [sp, #0xE0]
    ldr  x30,      [sp, #0xF0]
    add  sp, sp, #0x110
    .endm

    // ---- one 128-byte vector slot: align, then branch to a trampoline --------
    .macro VEC_SLOT target
    .balign 0x80
    b   \target
    .endm

    .section .text._vectors, "ax"
    .balign 0x800                 // VBAR_EL1 requires 2 KiB alignment
    .globl __exception_vectors
__exception_vectors:
    // --- Current EL with SP0 (EL1t) -- we never run on SP0; treat as fatal ---
    VEC_SLOT __vec_other          // 0x000 Synchronous
    VEC_SLOT __vec_other          // 0x080 IRQ / vIRQ
    VEC_SLOT __vec_other          // 0x100 FIQ / vFIQ
    VEC_SLOT __vec_other          // 0x180 SError / vSError
    // --- Current EL with SPx (EL1h) -- this is where our kernel runs ---------
    VEC_SLOT __vec_sync           // 0x200 Synchronous  <-- real handler (M1)
    VEC_SLOT __vec_other          // 0x280 IRQ / vIRQ   (masked in M1)
    VEC_SLOT __vec_other          // 0x300 FIQ / vFIQ   (masked in M1)
    VEC_SLOT __vec_other          // 0x380 SError / vSError
    // --- Lower EL using AArch64 (EL0) ---------------------------------------
    VEC_SLOT __vec_el0_sync       // 0x400 Synchronous  <-- real handler (M4 SVC)
    VEC_SLOT __vec_other          // 0x480 IRQ          (no EL0 IRQ source yet)
    VEC_SLOT __vec_other          // 0x500 FIQ
    VEC_SLOT __vec_other          // 0x580 SError
    // --- Lower EL using AArch32 -- no AArch32 guests; fatal ------------------
    VEC_SLOT __vec_other          // 0x600 Synchronous
    VEC_SLOT __vec_other          // 0x680 IRQ
    VEC_SLOT __vec_other          // 0x700 FIQ
    VEC_SLOT __vec_other          // 0x780 SError
    .balign 0x80                  // pad slot 15 to a full 128 B: table == 0x800

    // ---- trampolines (live just past the 2 KiB table, still KEEP'd) ----------
__vec_sync:                       // Current-EL-SPx synchronous: brk/undef/abort
    SAVE_CONTEXT
    mov  x1, #0                   // source = 0: synchronous, current EL (SPx)
    b    __trap_dispatch
__vec_other:                      // every other vector: unexpected -> fatal
    SAVE_CONTEXT
    mov  x1, #1                   // source = 1: unexpected vector
    b    __trap_dispatch
__vec_el0_sync:                   // Lower-EL-AArch64 synchronous: EL0 SVC (M4)
    SAVE_CONTEXT
    mov  x0, sp                   // AAPCS64 arg0 = &Frame (x0..x30, ELR, SPSR)
    bl   aarch64_el0_sync_handler // user.rs: records the syscall + longjmps
                                  //   back into the kernel; `-> !`, no return
    b    .                        // defensive park: the handler never returns
__trap_dispatch:
    mov  x0, sp                   // AAPCS64 arg0 = &TrapFrame
    bl   aarch64_trap_handler     // extern "C" in trap.rs; may halt (Halt path)
    RESTORE_CONTEXT               // Resume path: pop state (elr maybe +4)
    eret
"#
);

//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 serial + M1 traps + M2
//! tasks + M3 MMU + M4 user/ring boundary).
//!
//! Single crate where `unsafe`/asm is allowed (framekernel rule,
//! KERNEL-FOUNDATION-SPEC.md §1). Raw pokes live in `arch/`; THIS file is the
//! thin, mostly-safe facade the `kernel` crate is allowed to call:
//!
//! M0: [`serial_init`], [`serial_write_byte`], [`serial_write_str`], [`halt`].
//! M1: [`install_traps`], [`breakpoint`], [`set_trap_hook`], [`TrapInfo`] /
//!     [`TrapKind`] / [`TrapAction`] (the safe trap-dispatch ABI).
//! M2: [`Task`], [`task_create`], [`yield_to`], [`TaskStack`], [`current_task`]
//!     (cooperative context switch; the saved SP is the whole per-task handle).
//! M3: [`mmu_init`], [`mmu_selftest`] (MMU bring-up + map/remap self-test; the
//!     shared typed table layer is `mmu.rs`).
//! M4 (this milestone): [`user_demo`] — drop the CPU to unprivileged mode
//!     (x86_64 ring 3 / aarch64 EL0) at a tiny user stub, have it issue ONE
//!     syscall (`int 0x80` / `svc #0`) that traps back into the kernel,
//!     observe it (and its magic argument) from the safe handler, and return
//!     the CPU to the kernel. The whole round-trip + all new unsafe/asm lives
//!     in `arch::user`; the kernel crate only branches on the returned bool.
//!
//! POLICY lives in safe Rust: tb-hal's per-arch asm marshals a raw
//! `TrapFrame`, an `extern \"C\"` handler (the ONLY raw-frame deref) builds a
//! safe [`TrapInfo`] and calls the registered hook via [`dispatch_trap`]; the
//! default hook returns [`TrapAction::Halt`].

#![no_std]
#![deny(missing_docs)]

use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

mod arch;
mod mmu; // M3: shared typed page-table layer (PageTable512/Frame4K + entry math).

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: a loop over [`serial_write_byte`]; performs no `unsafe`.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

// ===========================================================================
// M1: trap installation + safe dispatch ABI
// ===========================================================================

/// Install real CPU exception/interrupt handling for the current architecture.
///
/// * x86_64: load a PERMANENT flat 64-bit GDT (null, ring0 code, ring0 data,
///   64-bit TSS, ring3 user code/data), reload `CS`/data segments, `ltr` the
///   TSS, then load a 256-entry IDT of 64-bit interrupt gates. `#DF`/NMI/`#MC`
///   route through TSS IST stacks.
/// * aarch64: point `VBAR_EL1` at the 2 KiB-aligned, 16×128-byte vector table.
///
/// Idempotent. Call once early from `rust_main`, before [`breakpoint`].
pub fn install_traps() {
    arch::install_traps();
}

/// Execute a software breakpoint trap on the current architecture.
///
/// * x86_64: `int3` (`#BP`, vector 3) — a TRAP whose CPU-saved `RIP` already
///   points PAST the instruction, so it resumes automatically on
///   [`TrapAction::Resume`].
/// * aarch64: `brk #0` — a SYNCHRONOUS exception (`ESR_EL1.EC = 0x3C`) whose
///   `ELR_EL1` points AT the instruction; the trap entry advances `ELR_EL1` by
///   4 on [`TrapAction::Resume`].
pub fn breakpoint() {
    arch::breakpoint();
}

/// The architecture-neutral classification of a trap, derived in the per-arch
/// `extern \"C\"` handler from the raw cause (vector + error code on x86_64,
/// `ESR_EL1.EC` on aarch64).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapKind {
    /// Software breakpoint: x86 `#BP` (vector 3) / aarch64 `brk` (EC `0x3C`).
    Breakpoint,
    /// Page / data fault: x86 `#PF` (vector 14) / aarch64 data abort
    /// (EC `0x24`/`0x25`). [`TrapInfo::fault_addr`] holds the faulting address.
    PageFault,
    /// Undefined / invalid instruction: x86 `#UD` (vector 6) / aarch64 Unknown
    /// (EC `0x00`).
    Undefined,
    /// Any other trap not specially classified above.
    Other,
}

/// What the dispatch hook asks tb-hal to do after a trap is handled.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapAction {
    /// Return from the trap entry so execution continues past the trapping
    /// instruction (x86: `iretq`; aarch64: `eret`, advancing `ELR_EL1` by 4 for
    /// the at-instruction synchronous breakpoint).
    Resume,
    /// Do not return; park the vCPU forever. Used for fatal faults and as the
    /// default policy when no hook is registered.
    Halt,
}

/// A safe, fully-owned description of a trap, handed to the dispatch hook.
///
/// Built inside tb-hal's per-arch handler from the raw `TrapFrame`; it borrows
/// nothing from the raw frame, so the hook (in the otherwise-`forbid(unsafe)`
/// kernel crate) can read it freely.
#[derive(Clone, Copy, Debug)]
pub struct TrapInfo {
    /// The architecture-neutral kind of this trap.
    pub kind: TrapKind,
    /// Raw cause word. x86_64: `(vector << 32) | (error_code & 0xFFFF_FFFF)`.
    /// aarch64: the full `ESR_EL1` value (EC = bits `[31:26]`).
    pub cause: u64,
    /// Faulting address for memory faults (x86 `CR2` for `#PF`; aarch64
    /// `FAR_EL1` for a data abort), otherwise `0`.
    pub fault_addr: u64,
    /// The trapping instruction pointer (x86 saved `RIP`; aarch64 `ELR_EL1`).
    pub pc: u64,
}

/// Storage for the registered trap hook: a `fn(&TrapInfo) -> TrapAction`
/// reinterpreted as `usize`. `0` means \"no hook registered → default halt\".
static TRAP_HOOK: AtomicUsize = AtomicUsize::new(0);

/// The default policy when no hook has been registered: always halt.
fn default_trap_hook(_info: &TrapInfo) -> TrapAction {
    TrapAction::Halt
}

/// Register the safe trap-dispatch policy hook.
///
/// A plain `fn(&TrapInfo) -> TrapAction`; it lives in safe Rust (e.g. the
/// kernel crate under `#![forbid(unsafe_code)]`) and decides per-trap whether
/// to [`TrapAction::Resume`] or [`TrapAction::Halt`].
pub fn set_trap_hook(hook: fn(&TrapInfo) -> TrapAction) {
    TRAP_HOOK.store(hook as usize, Ordering::Release);
}

/// Dispatch a trap to the registered hook (or the default halt policy).
///
/// Called by each per-arch `extern \"C\"` handler with a [`TrapInfo`] it built
/// from the raw frame: the safe boundary between the raw-frame deref
/// (per-arch, `unsafe`) and the policy hook (safe).
pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction {
    let raw = TRAP_HOOK.load(Ordering::Acquire);
    if raw == 0 {
        return default_trap_hook(info);
    }
    // SAFETY: `raw` is non-zero, so it was produced by `set_trap_hook` from a
    // valid `fn(&TrapInfo) -> TrapAction` via `hook as usize`. A function
    // pointer and `usize` are pointer-sized; this is the exact inverse cast.
    let hook: fn(&TrapInfo) -> TrapAction =
        unsafe { core::mem::transmute::<usize, fn(&TrapInfo) -> TrapAction>(raw) };
    hook(info)
}

// ===========================================================================
// M2: cooperative tasks + context switch
// ===========================================================================
//
// Saved-context model (callee-saved-on-stack): `yield_to` saves ONLY the
// callee-saved registers of the outgoing task on its own stack and records the
// resulting SP in that task's slot; resuming is \"load saved SP, pop the
// callee-saved set, return\". A single `usize` (the saved SP) is the whole
// per-task context. Caller-saved regs are dead across the call, so unsaved.
//
// Verified ABI facts (do NOT change register sets / frame layouts without
// re-reading): x86-64 SysV psABI §3.2.1 callee-saved = {rbx, rbp, r12..r15}
// (+rsp); §3.2.2 \"(%rsp + 8) is a multiple of 16\" at entry. AAPCS64 §6.1.1
// callee-saved = r19..r29 + SP (r29=FP, r30=LR carries the resume address);
// §6.4.5.1 \"SP mod 16 = 0\". Initial-frame fabrication (OSDev \"Brendan's
// Multi-tasking Tutorial\"): a fake callee-saved frame whose return address /
// LR is the entry, so the FIRST switch \"returns\" into `entry`. No FP/SIMD
// state is switched (both targets are soft-float).

/// Number of task slots tb-hal tracks, INCLUDING slot 0 (the bootstrap context
/// `rust_main` runs on). Eight leaves headroom without a heap.
const MAX_TASKS: usize = 8;

/// Per-slot saved stack pointer — the WHOLE saved context of a suspended task.
/// `0` means \"no saved context\". `AtomicUsize` for safe interior mutability
/// (single-core cooperative, not racing).
static TASK_SP: [AtomicUsize; MAX_TASKS] = [const { AtomicUsize::new(0) }; MAX_TASKS];

/// Slot index of the task currently executing on this (single) core.
static CURRENT_TASK: AtomicUsize = AtomicUsize::new(0);

/// Next free slot in [`TASK_SP`]; slot 0 is the bootstrap context.
static NEXT_TASK_SLOT: AtomicUsize = AtomicUsize::new(1);

/// Smallest stack [`task_create`] accepts, in `usize` words.
const MIN_STACK_WORDS: usize = 64;

/// An opaque handle to a cooperative kernel task: the slot index into tb-hal's
/// internal saved-SP table. `Copy`; convertible to/from a raw `usize` (see
/// [`Task::raw`]) so the `forbid(unsafe_code)` kernel can stash handles in
/// `AtomicUsize` statics.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Task(usize);

impl Task {
    /// The raw slot index of this handle, for stashing in an `AtomicUsize`.
    pub fn raw(self) -> usize {
        self.0
    }

    /// Rebuild a handle from a value previously obtained via [`Task::raw`].
    ///
    /// Safe: an invalid index cannot cause memory unsafety — it is rejected
    /// fail-closed by [`yield_to`] (bounds + saved-context check).
    pub fn from_raw(raw: usize) -> Self {
        Task(raw)
    }
}

/// Handle of the task currently executing (slot 0 — the bootstrap context —
/// until the first [`yield_to`] after [`task_create`]).
pub fn current_task() -> Task {
    Task(CURRENT_TASK.load(Ordering::Relaxed))
}

/// Fail-closed termination for misuse of the M2 task API: report over serial
/// (best-effort) and park the core. Never returns.
fn task_api_fatal(msg: &str) -> ! {
    serial_write_str(\"tb-hal: task: \");
    serial_write_str(msg);
    serial_write_byte(b'\\n');
    halt()
}

/// Create a cooperative task that starts executing `entry` the first time
/// somebody [`yield_to`]s it.
///
/// `stack` is caller-provided `'static` memory (see [`TaskStack`]; tb-hal does
/// NOT allocate). The arch backend fabricates the INITIAL context frame at the
/// 16-byte-aligned-down top of `stack` so the first switch \"returns\" into
/// `entry` with an ABI-conformant stack.
///
/// `entry` must never return. Fatal (reports + halts) if the stack is too
/// small or all task slots are used.
pub fn task_create(stack: &'static mut [usize], entry: fn()) -> Task {
    if stack.len() < MIN_STACK_WORDS {
        task_api_fatal(\"task_create: stack too small\");
    }
    let slot = NEXT_TASK_SLOT.fetch_add(1, Ordering::Relaxed);
    if slot >= MAX_TASKS {
        task_api_fatal(\"task_create: too many tasks\");
    }
    let sp = arch::task_stack_init(stack, entry);
    TASK_SP[slot].store(sp, Ordering::Release);
    Task(slot)
}

/// Cooperatively switch from the current context to `next`.
///
/// Saves the callee-saved registers + SP of the CURRENT task (on its own
/// stack), records the resulting SP, then loads `next`'s saved SP, restores
/// its callee-saved registers and returns into it. Yielding to the current
/// task is a no-op; an invalid handle is fatal (report + halt).
pub fn yield_to(next: Task) {
    if next.0 >= MAX_TASKS {
        task_api_fatal(\"yield_to: invalid task handle\");
    }
    let prev = CURRENT_TASK.load(Ordering::Relaxed);
    if prev == next.0 {
        return; // self-yield: nothing to switch
    }
    let next_sp = TASK_SP[next.0].load(Ordering::Acquire);
    if next_sp == 0 {
        task_api_fatal(\"yield_to: target has no saved context\");
    }
    CURRENT_TASK.store(next.0, Ordering::Relaxed);
    // SAFETY: `next_sp` was produced by `arch::task_stack_init` (fabricated
    // frame) or a previous `ctx_switch` save; both leave a well-formed
    // callee-saved frame at that SP. `TASK_SP[prev].as_ptr()` is a valid
    // 'static atomic for the single word `ctx_switch` stores. Single core +
    // cooperative: no other context can touch either slot mid-switch.
    unsafe { arch::ctx_switch(TASK_SP[prev].as_ptr(), next_sp) }
}

/// A statically-allocatable, 16-byte-aligned kernel task stack of `WORDS`
/// `usize` words, takeable exactly once as `&'static mut [usize]`.
///
/// Lets the `#![forbid(unsafe_code)]` kernel OWN its static stack arrays and
/// still mint the unique `&'static mut` [`task_create`] requires. The atomic
/// one-shot gate makes aliased handouts impossible; a second [`TaskStack::take`]
/// is fatal.
#[repr(C, align(16))]
pub struct TaskStack<const WORDS: usize> {
    mem: UnsafeCell<[usize; WORDS]>,
    taken: AtomicBool,
}

// SAFETY: the ONLY route to the inner array is `take()`, whose swap-once gate
// hands out at most one `&'static mut` ever, so shared references to the cell
// never alias the interior data.
unsafe impl<const WORDS: usize> Sync for TaskStack<WORDS> {}

impl<const WORDS: usize> TaskStack<WORDS> {
    /// A new zeroed stack; `const`, so it can initialise a kernel `static`.
    pub const fn new() -> Self {
        TaskStack {
            mem: UnsafeCell::new([0; WORDS]),
            taken: AtomicBool::new(false),
        }
    }

    /// Hand out the stack as `&'static mut [usize]` — exactly once. A second
    /// call on the same static is fatal (fail-closed).
    pub fn take(&'static self) -> &'static mut [usize] {
        if self.taken.swap(true, Ordering::AcqRel) {
            task_api_fatal(\"TaskStack::take: taken twice\");
        }
        // SAFETY: the swap guarantees this runs at most once per static, so the
        // `&mut` minted here is unique for `'static`; `UnsafeCell` makes
        // mutating the interior of an immutable `static` well-defined.
        let array: &'static mut [usize; WORDS] = unsafe { &mut *self.mem.get() };
        &mut array[..]
    }
}

// ===========================================================================
// M3: MMU bring-up + map/remap self-test
// ===========================================================================
//
// The typed table layer both backends share is `mmu.rs` (pure safe Rust); ALL
// new unsafe + asm (CR3/EFER/invlpg, MAIR/TCR/TTBR0/SCTLR, dsb/isb/tlbi, the
// mapped-VA derefs) lives in `arch/`. The kernel only sees the two safe fns.

/// Bring the MMU to the M3 baseline. Call ONCE from `rust_main`, AFTER
/// [`install_traps`] (a broken mapping then reports via the trap path instead
/// of an opaque hang / triple fault).
///
/// * x86_64: paging is already LIVE; this programs `EFER.NXE` so PTE bit 63
///   (NX) is honoured. `IA32_PAT` keeps its power-on default.
/// * aarch64: brings the MMU up from cold — identity tables (L1[0] Device for
///   the PL011 gigabyte, L1[1] Normal-WB for RAM, AF on every leaf), then
///   `MAIR_EL1`/`TCR_EL1`/`TTBR0_EL1` → `isb` → `SCTLR_EL1.{M,C,I}` → `isb`.
pub fn mmu_init() {
    arch::mmu_init();
}

/// Run the in-HAL MMU map/remap self-test; `true` = pass.
///
/// Maps `TEST_VA` (x86_64 `0x4000_0000` / aarch64 `0x8000_0000`, both OUTSIDE
/// the identity region) to frame A, writes a magic through `TEST_VA`, verifies
/// via frame A's identity address, remaps to frame B (x86: PTE rewrite +
/// `invlpg`; aarch64: full Break-Before-Make + `tlbi`), and verifies the read
/// through `TEST_VA` now sees frame B. Tables/frames are static, 4096-aligned,
/// `.bss`-resident; every raw deref stays in tb-hal's arch backends.
pub fn mmu_selftest() -> bool {
    arch::mmu_selftest()
}

// ===========================================================================
// M4: user/ring boundary (this milestone)
// ===========================================================================
//
// The privileged/unprivileged split end-to-end: tb-hal drops the CPU to ring 3
// (x86_64) / EL0 (aarch64), runs a tiny user stub, the stub issues ONE syscall
// that traps back into the kernel, the safe handler records it, and the CPU
// returns to the kernel. ALL new unsafe/asm lives in `arch::user`; this facade
// just forwards. The kernel crate stays `#![forbid(unsafe_code)]`.

/// M4 user/ring round-trip; `true` = the syscall was observed from user mode
/// with the expected magic argument (`0xCAFE`).
///
/// tb-hal sets up a user-accessible code page + user stack page (via the M3
/// `mmu` machinery, with USER permission bits at every level of the walk),
/// drops the CPU to unprivileged mode at the stub, the stub issues the syscall
/// (x86_64 `int 0x80` with `rax = 0xCAFE`; aarch64 `svc #0` with
/// `x0 = 0xCAFE`), the kernel-side handler records the argument and switches
/// the CPU back into a kernel continuation, and `user_demo` reads the recorded
/// flag/argument. The whole round-trip — USER mappings, the privileged drop
/// (`iretq` / `eret`), the user stub, the syscall entry and the kernel return
/// — lives in `arch::user`; all the new unsafe + assembly is confined there.
pub fn user_demo() -> bool {
    arch::user_demo()
}

//! TABOS kernel entry shim (M4: user/ring boundary).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust. THIS file is the
//! single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker
//! to expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into),
//! and the `unsafe_code` lint flags it. All real unsafe + assembly is confined
//! to tb-hal (KERNEL-FOUNDATION-SPEC.md §1).
//!
//! M2 (kept verbatim) proves the cooperative context switch: two kernel tasks
//! (A and B) on kernel-owned static stacks voluntarily `yield_to` each other
//! for `ROUND_TRIPS` strict A,B,A,B round-trips. tb-hal switches only the ABI
//! callee-saved registers + SP, so each task carries locals ACROSS every yield
//! as a REGISTER-INTEGRITY CANARY; divergence prints \"M2: FAIL <why>\". On
//! success it prints \"M2: context-switch OK\". The M0 serial hello and the M1
//! breakpoint round-trip are kept verbatim ahead of it.
//!
//! M3 (kept) appends the MMU proof: `mmu_init()`, a serial line proving the
//! UART mapping survived the enable, then `mmu_selftest()` (map -> write ->
//! verify -> remap -> re-verify). DoD marker: \"M3: mmu OK\".
//!
//! M4 (this milestone) appends the user/ring boundary proof. After M3, the
//! kernel calls `tb_hal::user_demo()`: tb-hal sets up USER-accessible code +
//! stack pages (M3 mmu layer + USER permission bits), drops the CPU to
//! unprivileged mode (x86_64 ring 3 / aarch64 EL0) at a tiny user stub, the
//! stub issues ONE syscall (`int 0x80` / `svc #0`) that traps back into the
//! kernel, the safe handler records it (+ its magic arg) and returns the CPU
//! to the kernel. `user_demo()` returns true iff the syscall was observed from
//! user mode with arg == 0xCAFE. DoD marker: \"M4: user/ring OK\". ALL the new
//! unsafe/asm lives in tb-hal; this crate calls one safe fn and branches on a
//! bool.

#![no_std]
#![no_main]

use core::hint::black_box;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use tb_hal::{Task, TaskStack, TrapAction, TrapInfo, TrapKind};

/// Ping-pong round-trips (A→B→A counts as one). DoD asks for >= 1000.
const ROUND_TRIPS: usize = 1000;

/// `TURN` value meaning \"task A must run this half-round\".
const TURN_A: usize = 0;
/// `TURN` value meaning \"task B must run this half-round\".
const TURN_B: usize = 1;

/// Initial value of task A's rotating-pattern canary (arbitrary, asymmetric).
const PAT_A_INIT: usize = 0xA5A5_5A5A_DEAD_BEEF;
/// Initial value of task B's rotating-pattern canary (different from A's).
const PAT_B_INIT: usize = 0x0F0F_F0F0_CAFE_F00D;

// --- M2 scheduler bookkeeping (all in THIS forbid-class crate, all safe) ----

/// Task A's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_A: TaskStack<4096> = TaskStack::new();
/// Task B's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_B: TaskStack<4096> = TaskStack::new();

/// Task A's handle as `Task::raw()`, stashed so task B can yield back to A.
static TASK_A_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);
/// Task B's handle as `Task::raw()`, stashed so task A can yield to B.
static TASK_B_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Bootstrap context's handle as `Task::raw()` (slot 0), stashed BEFORE the
/// ping-pong starts so task A can hand the CPU back to `rust_main` after the
/// M2 verdict — M3/M4 then run in the bootstrap context.
static BOOT_TASK_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Set by task A immediately after the M2 success marker and right before it
/// yields back to the bootstrap context. `rust_main` refuses to start M3
/// without it (fail-closed against any stray resume of slot 0).
static M2_PASSED: AtomicBool = AtomicBool::new(false);

/// Whose half-round it is: the strict-alternation flag (TURN_A / TURN_B).
static TURN: AtomicUsize = AtomicUsize::new(TURN_A);

/// Shared increment counter: A sees it == 2*i at round i, B sees == 2*j + 1.
static COUNTER: AtomicUsize = AtomicUsize::new(0);

/// Set by task B after it audited its own canaries on its final round.
static B_VERIFIED: AtomicBool = AtomicBool::new(false);

/// Boot entry. tb-hal's per-arch `_start` jumps here after setting up a stack,
/// zeroing `.bss`, and placing the boot-info pointer in arg0 (SysV `rdi` on
/// x86_64 = `hvm_start_info` phys addr; AAPCS64 `x0` on aarch64 = FDT blob).
#[unsafe(no_mangle)]
pub extern \"C\" fn rust_main(boot_info: usize) -> ! {
    // M0..M4 ignore boot_info; a later milestone parses hvm_start_info / FDT.
    let _ = boot_info;

    // --- M0 proof (kept verbatim): serial first-light ----------------------
    tb_hal::serial_init();
    tb_hal::serial_write_str(\"hello from rust_main\\n\");

    // --- M1 proof (kept): install traps, take a breakpoint, resume ---------
    tb_hal::install_traps();
    tb_hal::set_trap_hook(trap_hook);
    tb_hal::serial_write_str(\"trap-test: triggering breakpoint\\n\");
    tb_hal::breakpoint(); // int3 (x86_64) / brk #0 (aarch64); hook -> Resume
    tb_hal::serial_write_str(\"trap-test: resumed past breakpoint\\n\");
    tb_hal::serial_write_str(\"M1: traps OK\\n\");

    // --- M2 proof (kept): cooperative context-switch ping-pong -------------
    tb_hal::serial_write_str(\"ctx-test: starting ping-pong\\n\");
    BOOT_TASK_RAW.store(tb_hal::current_task().raw(), Ordering::Release);
    let task_a = tb_hal::task_create(STACK_A.take(), task_a_main);
    let task_b = tb_hal::task_create(STACK_B.take(), task_b_main);
    TASK_A_RAW.store(task_a.raw(), Ordering::Release);
    TASK_B_RAW.store(task_b.raw(), Ordering::Release);
    tb_hal::yield_to(task_a);

    // Fail-closed gate: the ONLY legal way back here is task A's post-verdict
    // hand-off. Anything else (a stray yield to slot 0) is an M2 failure.
    if !M2_PASSED.load(Ordering::Acquire) {
        fail(\"bootstrap context resumed before the M2 verdict\");
    }

    // --- M3: MMU bring-up + map/remap self-test ----------------------------
    tb_hal::serial_write_str(\"mmu-test: init\\n\");
    tb_hal::mmu_init();
    tb_hal::serial_write_str(\"mmu-test: enabled, serial alive\\n\");
    if tb_hal::mmu_selftest() {
        tb_hal::serial_write_str(\"M3: mmu OK\\n\"); // <-- the M3 DoD marker
    } else {
        tb_hal::serial_write_str(\"M3: FAIL\\n\");
        tb_hal::halt();
    }

    // --- M4: user/ring boundary -- drop to ring3/EL0, syscall, trap back ----
    // tb-hal maps USER-accessible code + stack pages (M3 mmu layer + USER
    // permission bits), drops the CPU to unprivileged mode at a tiny user
    // stub, the stub issues ONE syscall (int 0x80 / svc #0) that traps back
    // into the kernel, the safe handler records it (+ its magic arg) and the
    // CPU returns here. user_demo() is true iff the syscall was seen from user
    // mode with arg == 0xCAFE. All the new unsafe/asm lives in tb-hal; this
    // forbid(unsafe_code)-class crate only branches on the bool.
    tb_hal::serial_write_str(\"user-test: entering unprivileged mode\\n\");
    if tb_hal::user_demo() {
        tb_hal::serial_write_str(\"M4: user/ring OK\\n\"); // <-- the M4 DoD marker
    } else {
        tb_hal::serial_write_str(\"M4: FAIL\\n\");
    }
    tb_hal::halt()
}

/// Task A (\"ping\"): drives `ROUND_TRIPS` strict A,B,A,B round-trips against
/// task B, renders the M2 verdict, then hands the CPU back to the bootstrap
/// context so `rust_main` can run the M3/M4 sequence.
fn task_a_main() {
    let task_b = Task::from_raw(TASK_B_RAW.load(Ordering::Acquire));

    let mut a_loops: usize = 0; // canary 1: monotonic loop count
    let mut a_sum: usize = 0; // canary 2: accumulator over the index
    let mut a_pat: usize = PAT_A_INIT; // canary 3: rotating bit pattern

    let mut i: usize = 0;
    while i < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_A {
            fail(\"A: turn flag not A at round start\");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * i {
            fail(\"A: shared counter out of sequence\");
        }
        if black_box(a_loops) != i {
            fail(\"A: local loop canary corrupted\");
        }
        COUNTER.store(c + 1, Ordering::Release);
        a_loops = black_box(a_loops) + 1;
        a_sum = black_box(a_sum).wrapping_add(i);
        a_pat = black_box(a_pat).rotate_left(1);
        TURN.store(TURN_B, Ordering::Release);

        tb_hal::yield_to(task_b); // <-- the cooperative switch under test

        if TURN.load(Ordering::Acquire) != TURN_A {
            fail(\"A: alternation broken after resume\");
        }
        i += 1;
    }

    let mut want_sum: usize = 0;
    let mut want_pat: usize = PAT_A_INIT;
    let mut k: usize = 0;
    while k < ROUND_TRIPS {
        want_sum = black_box(want_sum).wrapping_add(k);
        want_pat = black_box(want_pat).rotate_left(1);
        k += 1;
    }
    if black_box(a_loops) != ROUND_TRIPS {
        fail(\"A: final loop count wrong\");
    }
    if black_box(a_sum) != want_sum {
        fail(\"A: final sum canary wrong\");
    }
    if black_box(a_pat) != want_pat {
        fail(\"A: final pattern canary wrong\");
    }
    if COUNTER.load(Ordering::Acquire) != 2 * ROUND_TRIPS {
        fail(\"A: final shared counter wrong\");
    }
    if !B_VERIFIED.load(Ordering::Acquire) {
        fail(\"A: task B never reported success\");
    }

    tb_hal::serial_write_str(\"M2: context-switch OK\\n\"); // <-- the M2 DoD marker

    M2_PASSED.store(true, Ordering::Release);
    tb_hal::yield_to(Task::from_raw(BOOT_TASK_RAW.load(Ordering::Acquire)));

    fail(\"A: resumed after handing control back to bootstrap\")
}

/// Task B (\"pong\"): mirror half of the ping-pong, with its own canary locals
/// live across every yield. Audits its canaries on the FINAL round before the
/// last yield and publishes the verdict via `B_VERIFIED`.
fn task_b_main() {
    let task_a = Task::from_raw(TASK_A_RAW.load(Ordering::Acquire));

    let mut b_loops: usize = 0; // canary 1: monotonic loop count
    let mut b_sum: usize = 0; // canary 2: accumulator over the index
    let mut b_pat: usize = PAT_B_INIT; // canary 3: rotating bit pattern

    let mut j: usize = 0;
    while j < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_B {
            fail(\"B: turn flag not B at round start\");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * j + 1 {
            fail(\"B: shared counter out of sequence\");
        }
        if black_box(b_loops) != j {
            fail(\"B: local loop canary corrupted\");
        }
        COUNTER.store(c + 1, Ordering::Release);
        b_loops = black_box(b_loops) + 1;
        b_sum = black_box(b_sum).wrapping_add(j);
        b_pat = black_box(b_pat).rotate_left(1);
        j += 1;

        if j == ROUND_TRIPS {
            let mut want_sum: usize = 0;
            let mut want_pat: usize = PAT_B_INIT;
            let mut k: usize = 0;
            while k < ROUND_TRIPS {
                want_sum = black_box(want_sum).wrapping_add(k);
                want_pat = black_box(want_pat).rotate_left(1);
                k += 1;
            }
            if black_box(b_loops) != ROUND_TRIPS {
                fail(\"B: final loop count wrong\");
            }
            if black_box(b_sum) != want_sum {
                fail(\"B: final sum canary wrong\");
            }
            if black_box(b_pat) != want_pat {
                fail(\"B: final pattern canary wrong\");
            }
            B_VERIFIED.store(true, Ordering::Release);
        }

        TURN.store(TURN_A, Ordering::Release);
        tb_hal::yield_to(task_a); // <-- the cooperative switch under test
    }

    fail(\"B: resumed after completing all rounds\")
}

/// Emit the M2 failure verdict (\"M2: FAIL <why>\") over serial and park the
/// core. Never returns; the run scripts then miss the later markers.
fn fail(why: &str) -> ! {
    tb_hal::serial_write_str(\"M2: FAIL \");
    tb_hal::serial_write_str(why);
    tb_hal::serial_write_byte(b'\\n');
    tb_hal::halt()
}

/// Safe trap-dispatch policy hook (kept from M1: policy lives in this
/// `forbid(unsafe_code)`-class crate, not in tb-hal's raw entry asm).
fn trap_hook(info: &TrapInfo) -> TrapAction {
    match info.kind {
        TrapKind::Breakpoint => {
            tb_hal::serial_write_str(\"trap: breakpoint, resuming\\n\");
            TrapAction::Resume
        }
        _ => {
            tb_hal::serial_write_str(\"trap: fatal fault, halting\\n\");
            tb_hal::serial_write_str(\"  cause=\");
            write_hex_u64(info.cause);
            tb_hal::serial_write_str(\" fault_addr=\");
            write_hex_u64(info.fault_addr);
            tb_hal::serial_write_str(\" pc=\");
            write_hex_u64(info.pc);
            tb_hal::serial_write_byte(b'\\n');
            TrapAction::Halt
        }
    }
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
/// Pure safe Rust (no `core::fmt`, no allocation).
fn write_hex_u64(value: u64) {
    tb_hal::serial_write_str(\"0x\");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        tb_hal::serial_write_byte(c);
        shift -= 4;
    }
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str(\"panic\\n\");
    tb_hal::halt()
}
